INSERT INTO targets VALUES(1,'apache-httpd','Apache HTTP Server','2.4','CIS Apache HTTP Server 2.4 Benchmark v2.3.0','2026-06-20T01:19:59.173Z','2026-06-20T01:19:59.173Z');
INSERT INTO targets VALUES(2,'nginx','Nginx','3.0','CIS NGINX Benchmark v3.0.0','2026-06-20T01:42:56.261Z','2026-06-20T01:42:56.261Z');
INSERT INTO targets VALUES(3,'ssh','OpenSSH Server','9.0','CIS Ubuntu Linux 24.04 LTS Benchmark v2.0.0 — Section 5.1','2026-06-20T17:38:22.149Z','2026-06-20T17:38:22.149Z');
INSERT INTO targets VALUES(4,'mysql','MySQL','1.0','CIS Oracle MySQL Enterprise Edition 5.6 Benchmark v2.0.0 ARCHIVE','2026-06-21T23:21:29.105Z','2026-06-21T23:21:29.105Z');
INSERT INTO misconfigurations VALUES('e5bedb85-c9d4-496f-b15a-690bc23932e3',1,'apache-httpd','ServerTokens','Full','Prod','N','N','L','P','N','N',5.0,5.0,'M','H','[]','CCE-27380-5','8.1','ServerTokens Full exposes detailed Apache version and module information, enabling attackers to target specific vulnerabilities for the disclosed version.','Set ''ServerTokens Prod'' to expose only the product name.','value','always','','{"description": "The ServerTokens directive controls the amount of information about the Apache server that is included in HTTP responses. Setting it to ''Full'' reveals detailed version and module information which can be exploited by attackers.", "potential_impact": ["Enables attackers to identify specific vulnerabilities for targeted attacks", "Increases the risk of automated exploitation due to known vulnerabilities", "Reduces the difficulty of crafting tailored exploits against disclosed modules"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends an HTTP request to any endpoint on the server and examines the Server header in the response.", "result": "The attacker gains detailed information about the Apache version and enabled modules, allowing them to craft targeted attacks."}, "metric_justifications": {"ac": "AC=L: The exposure of detailed server information is trivially exploitable by sending a standard HTTP request without any additional preconditions.", "c": "C=P: Discloses specific Apache version and module details, aiding in crafting precise exploits.", "i": "I=N: No direct modification or access to sensitive data is granted through the exposed information alone.", "a": "A=N: Availability of services is not directly impacted by exposing server tokens.", "gel": "GEL=M: Misconfigurations like this are frequently exploited due to their ease and effectiveness in aiding targeted attacks.", "grl": "GRL=H: There is extensive documentation available on how to properly configure ServerTokens for security."}}','2026-06-20T01:20:54.909Z','2026-06-20T02:23:34.177Z');
INSERT INTO misconfigurations VALUES('a0cb5507-cc24-4ef7-b65a-e5fd3ccee9fe',1,'apache-httpd','ServerTokens','OS','Prod','N','N','L','P','N','N',5.0,5.0,'M','H','[]','CCE-27380-5','8.1','ServerTokens OS exposes the operating system version in every HTTP response header, enabling attackers to precisely target known CVEs for the disclosed OS.','Set ''ServerTokens Prod'' to expose only the product name.','value','always','','{"description": "The ServerTokens directive controls what information about the server is disclosed in HTTP responses. Setting it to OS reveals the operating system version, which can be exploited by attackers to target specific vulnerabilities.", "potential_impact": ["Enables attackers to identify and exploit known CVEs for the exposed OS", "Increases the risk of targeted attacks based on precise OS knowledge", "Reduces the difficulty of crafting exploits tailored to a specific environment"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends an HTTP request and examines the Server header in the response. For example: GET / HTTP/1.1\r\nHost: example.com", "result": "The attacker gains knowledge of the exact OS version, allowing them to search for specific vulnerabilities or exploits."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can easily discover the OS version by sending a standard HTTP request and examining the Server header.", "c": "Why C=P: The disclosure of the operating system version provides critical information to attackers, enabling targeted attacks.", "i": "Why I=N: There is no direct impact on data or configuration modification through this exposure alone.", "a": "Why A=N: Availability is not directly impacted by revealing OS details in HTTP headers.", "gel": "Why GEL=M: Misconfigurations like ServerTokens=OS are frequently exploited due to the ease of detection and exploitation.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure this directive for security."}}','2026-06-20T01:21:32.877Z','2026-06-20T02:25:28.437Z');
INSERT INTO misconfigurations VALUES('7436a34f-0b36-435b-bc59-894d9985da2e',1,'apache-httpd','ServerTokens','Minor','Prod','N','N','L','P','N','N',5.0,5.0,'M','H','[]','CCE-27380-5','8.1','ServerTokens set to ''Minor'' still provides more information than necessary, including the Apache version and some module details, which can be used by attackers to target specific vulnerabilities.','Set ''ServerTokens Prod'' or ''ProductOnly'' to minimize exposed server information.','value','always','','{"description": "The ServerTokens directive controls how much information about the server is disclosed in response headers. Setting it to ''Minor'' reveals more details than necessary, including the Apache version and some module information, which can be exploited by attackers.", "potential_impact": ["Discloses specific Apache version allowing attackers to target known vulnerabilities", "Provides detailed module information enabling attackers to craft attacks based on installed modules", "Increases reconnaissance efficiency for attackers looking to exploit server-specific configurations"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker sends an HTTP request and examines the Server header in the response. For example: GET / HTTP/1.1\r\nHost: example.com", "result": "The attacker gains detailed information about the Apache version and installed modules, facilitating targeted attacks."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can easily discover server details by sending a standard HTTP request without any special preconditions.", "c": "Why C=P: The directive discloses critical information such as the Apache version and module details, which are readable to attackers.", "i": "Why I=N: There is no direct impact on data or configuration modification through this disclosure alone.", "a": "Why A=N: Availability of services is not directly impacted by the information disclosed in ServerTokens.", "gel": "Why GEL=M: Misconfigurations like revealing server version details are frequently exploited due to their widespread use and ease of detection.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure ServerTokens for security."}}','2026-06-20T01:22:14.625Z','2026-06-20T02:27:35.412Z');
INSERT INTO misconfigurations VALUES('eb7ef5fb-242e-4123-af52-7cbbf88de2d7',1,'apache-httpd','ServerSignature','On','Off','N','N','L','P','N','N',5.0,5.0,'M','H','[]','CCE-27883-8','8.2','ServerSignature On discloses the Apache version and server name in error pages, allowing attackers to target known vulnerabilities specific to that version.','Set ''ServerSignature Off'' to remove the signature from server-generated documents.','value','always','','{"description": "The ServerSignature directive controls whether Apache includes its version number and other information in server-generated error messages. Setting it to ''On'' reveals detailed information about the server''s software version, which can be exploited by attackers to target known vulnerabilities specific to that version.", "potential_impact": ["Discloses the exact version of Apache being used", "Enables attackers to craft targeted attacks based on known vulnerabilities for that version", "Reduces the difficulty of reconnaissance efforts for an attacker"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends a crafted HTTP request designed to trigger an error page, such as sending a malformed URL or invalid HTTP method.", "result": "The server responds with an error message containing the Apache version number and other potentially sensitive information."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily discover the Apache version by simply triggering an error page, requiring no special privileges or conditions beyond sending a standard HTTP request.", "c": "Why C=P: The disclosure of the server''s software version and other information provides critical details that could be used to craft targeted attacks.", "i": "Why I=N: There is no direct impact on data modification or configuration changes due to this misconfiguration alone.", "a": "Why A=N: Availability is not directly impacted by ServerSignature being set to ''On''.", "gel": "Why GEL=M: Misconfigurations like revealing server version information are frequently exploited as they provide clear targets for attackers.", "grl": "Why GRL=H: There is extensive documentation and guidance available on how to properly configure the ServerSignature directive."}}','2026-06-20T01:22:52.191Z','2026-06-20T02:29:53.943Z');
INSERT INTO misconfigurations VALUES('6b1c674b-3905-43e4-911b-d3e37686536c',1,'apache-httpd','FileETag','All','MTime Size','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','8.4','FileETag All exposes inode numbers in ETag headers, allowing attackers to discern sensitive file metadata and potentially assist in other attacks.','Set ''FileETag None'' or ''FileETag MTime Size'' to avoid disclosing inode information.','value','always','','{"description": "The FileETag directive controls what information is included in ETag headers sent to clients. Setting it to ''All'' exposes inode numbers, which can be used by attackers to gather sensitive file metadata and aid in other attacks.", "potential_impact": ["Disclose detailed file metadata", "Assist in identifying specific files for further exploitation", "Facilitate reconnaissance efforts against the server"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends a standard HTTP request to retrieve resources from the web server. The response includes ETag headers with inode numbers.", "result": "The attacker gains detailed file metadata, which can be used for further reconnaissance or attacks."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can easily trigger this by sending a standard HTTP request to the server and examining the ETag headers.", "c": "Why C=P: The configuration discloses inode numbers, which are sensitive file metadata that could be used for reconnaissance or other attacks.", "i": "Why I=N: There is no direct impact on data modification or configuration changes through this misconfiguration alone.", "a": "Why A=N: Availability of the server and its resources remains unaffected by the exposure of inode numbers in ETag headers.", "gel": "Why GEL=M: Misconfigurations like exposing sensitive metadata via ETags are moderately common and can be exploited to aid other attacks.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure FileETag to avoid such issues."}}','2026-06-20T01:23:32.527Z','2026-06-20T02:31:52.558Z');
INSERT INTO misconfigurations VALUES('3bb4c49d-9698-4a0d-83be-83eeec0fa488',1,'apache-httpd','Timeout','300','10','N','N','L','N','N','P',5.0,5.0,'M','H','[]','CCE-27688-1','9.1','A high Timeout value of 300 seconds allows attackers to initiate many connections and keep them open for a long time, consuming server resources and making the service less responsive. This leads to gradual resource exhaustion but does not cause an immediate crash.','Set ''Timeout 10'' or shorter in the Apache configuration.','value','always','','{"description": "The Timeout directive sets the maximum number of seconds Apache will wait for certain events before closing inactive connections. A value of 300 seconds is dangerous because it allows attackers to maintain open connections for an extended period, leading to resource exhaustion and denial-of-service conditions.", "potential_impact": ["Consumes server resources such as memory and CPU cycles", "Reduces the responsiveness of the web service by keeping idle connections open", "Enables a slowloris attack where attackers can keep many connections open indefinitely"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends multiple HTTP requests to the server and keeps them open for up to 300 seconds, exhausting resources.", "result": "The web service becomes unresponsive due to resource exhaustion."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by sending multiple HTTP requests and keeping connections open for the full timeout period of 300 seconds, requiring no special preconditions beyond sending a request.", "c": "Why C=N: No sensitive information is disclosed or readable through this misconfiguration.", "i": "Why I=N: The configuration itself cannot be modified by an attacker due to this misconfiguration alone.", "a": "Why A=P: Availability of the web service is significantly impacted as server resources are consumed and connections remain open for extended periods, leading to denial-of-service conditions.", "gel": "Why GEL=M: This type of misconfiguration can be exploited with moderate frequency due to its potential impact on resource availability.", "grl": "Why GRL=H: Remediation documentation is widely available and straightforward, making it easy for administrators to correct this issue."}}','2026-06-20T01:24:17.565Z','2026-06-20T02:34:00.460Z');
INSERT INTO misconfigurations VALUES('4693f866-5f7e-496a-a8bc-e5a21a20c4d6',1,'apache-httpd','KeepAlive','Off','On','N','N','L','N','N','P',5.0,5.0,'M','H','[]','CCE-27456-3','9.2','Disabling KeepAlive increases the number of TCP connections required to serve requests, potentially leading to resource exhaustion and degraded performance during high traffic or DoS attacks.','Set ''KeepAlive On'' in httpd.conf.','value','always','','{"description": "The KeepAlive directive enables persistent HTTP connections to reduce latency for multiple requests from the same client. Disabling it (KeepAlive Off) can lead to increased server load and potential resource exhaustion during high traffic or DoS attacks.", "potential_impact": ["Increases server load due to higher number of TCP connections", "Leads to degraded performance under high traffic conditions", "Facilitates easier execution of Denial-of-Service (DoS) attacks"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker sends multiple HTTP requests with KeepAlive disabled, forcing the server to establish a new TCP connection for each request.", "result": "The server''s resources are overwhelmed by the increased number of connections, leading to degraded performance or service disruption."}, "metric_justifications": {"ac": "AC=L: An attacker can easily exploit this misconfiguration by sending multiple HTTP requests without establishing persistent connections, which is trivial and does not require any special preconditions.", "c": "C=N: No sensitive information is disclosed as a result of KeepAlive being disabled; however, the server''s availability may be compromised.", "i": "I=N: The misconfiguration does not allow for modification of data or configuration files on the server.", "a": "A=P: Availability is significantly impacted due to increased resource consumption and potential service disruption during high traffic or DoS attacks.", "gel": "GEL=M: This type of misconfiguration can be exploited moderately frequently as it affects performance and availability under certain conditions.", "grl": "GRL=H: There are extensive resources available for remediation, including official Apache documentation and security guidelines."}}','2026-06-20T01:24:55.764Z','2026-06-20T02:36:02.780Z');
INSERT INTO misconfigurations VALUES('08c87bfa-f86d-4d13-8953-06a682705798',1,'apache-httpd','MaxKeepAliveRequests','0','100','N','N','L','N','N','P',5.0,5.0,'M','H','[]','CCE-27830-9','9.3','Setting MaxKeepAliveRequests to 0 allows unlimited requests per connection, which can lead to resource exhaustion and gradual DoS conditions. However, the impact is not immediate system crash but rather degraded performance over time.','Set ''MaxKeepAliveRequests 100'' or a similar reasonable limit to mitigate DoS risks.','value','always','','{"description": "The MaxKeepAliveRequests directive sets the maximum number of requests that can be made on a persistent HTTP connection. Setting this value to 0 allows an unlimited number of requests per connection, which can lead to resource exhaustion and degrade server performance over time.", "potential_impact": ["Degraded server performance due to excessive keep-alive connections", "Resource exhaustion leading to denial-of-service conditions", "Increased load on the server''s resources such as CPU and memory"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker can repeatedly send requests over a single persistent connection without limit, causing resource depletion.", "result": "The server becomes unresponsive or performs poorly due to excessive keep-alive connections."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by sending an unlimited number of requests over a single persistent connection, requiring no special preconditions beyond making HTTP requests.", "c": "Why C=N: No sensitive information is disclosed or readable due to the misconfiguration.", "i": "Why I=N: The configuration cannot be modified directly through this attack vector.", "a": "Why A=P: Availability is significantly impacted as resource exhaustion can lead to denial-of-service conditions.", "gel": "Why GEL=M: This type of misconfiguration is moderately likely to be exploited due to its potential for causing significant performance degradation and DoS conditions.", "grl": "Why GRL=H: Remediation documentation is readily available, making it easy to correct the configuration."}}','2026-06-20T01:25:44.423Z','2026-06-20T02:38:00.477Z');
INSERT INTO misconfigurations VALUES('4a83463d-cbfc-4ebf-8467-1f7d9374e5de',1,'apache-httpd','KeepAliveTimeout','300','15','N','N','L','N','N','P',5.0,5.0,'M','H','[]','CCE-27330-0','9.4','A high KeepAliveTimeout value of 300 seconds increases the risk of resource exhaustion and DoS attacks, as it allows connections to remain open for longer periods, consuming more server resources.','Set ''KeepAliveTimeout 15'' or less in the Apache configuration.','value','always','','{"description": "The KeepAliveTimeout directive specifies how long Apache will wait for subsequent requests on an open connection. A value of 300 seconds is dangerous because it significantly increases the risk of resource exhaustion and Denial of Service (DoS) attacks by allowing connections to remain open longer, consuming more server resources.", "potential_impact": ["Exhausts server resources", "Increases susceptibility to DoS attacks", "Reduces overall system performance"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends multiple HTTP requests with Keep-Alive headers, keeping connections open for the full 300 seconds. This can be done using a simple script or tool.", "result": "The server''s resources are consumed by idle connections, leading to reduced availability and performance."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by sending HTTP requests with Keep-Alive headers, requiring no special preconditions beyond a standard HTTP request.", "c": "Why C=N: No sensitive information is disclosed or readable due to the misconfiguration alone.", "i": "Why I=N: The configuration itself cannot be modified directly through exploitation; however, server resources can be indirectly affected.", "a": "Why A=P: Availability is significantly impacted as idle connections consume valuable server resources, leading to potential DoS conditions.", "gel": "Why GEL=M: This type of misconfiguration is moderately common and can be exploited by attackers with basic knowledge.", "grl": "Why GRL=H: There are numerous remediation guides available for adjusting the KeepAliveTimeout setting."}}','2026-06-20T01:26:32.596Z','2026-06-20T02:40:02.852Z');
INSERT INTO misconfigurations VALUES('dd5ec089-e4d3-410b-a492-cd6ce1bff99a',1,'apache-httpd','LimitRequestLine','0','8190','N','N','L','N','N','P',5.0,5.0,'M','H','[]','CCE-27426-6','10.1','Setting LimitRequestLine to ''0'' allows an attacker to send arbitrarily large request lines, potentially causing a buffer overflow that can degrade server performance or lead to resource exhaustion. This results in partial availability impact but does not disclose sensitive information or allow for direct modification of data.','Set ''LimitRequestLine 8190''.','value','always','','{"description": "The LimitRequestLine directive sets an upper limit on the size of the request line sent by clients. Setting it to ''0'' disables this protection entirely, allowing attackers to send arbitrarily large request lines which can lead to buffer overflow conditions and degrade server performance.", "potential_impact": ["Degradation of server performance", "Resource exhaustion leading to denial of service", "Buffer overflow conditions that may allow for further exploitation"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends a POST request with an excessively long URI, such as: GET /verylonguriabcdefghijklmnopqrstuvwxyz1234567890 HTTP/1.1", "result": "The server may crash or become unresponsive due to buffer overflow conditions."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by sending a large request line, requiring no special privileges or knowledge beyond basic HTTP requests.", "c": "Why C=N: No sensitive information is disclosed as a result of the attack.", "i": "Why I=N: The configuration and data cannot be directly modified through this vulnerability.", "a": "Why A=P: Availability is partially impacted due to potential server crashes or resource exhaustion.", "gel": "Why GEL=M: This type of misconfiguration can be exploited with moderate frequency as it is a known security risk in web servers.", "grl": "Why GRL=H: There are numerous resources and documentation available for remediation, making it relatively easy to address."}}','2026-06-20T01:27:21.727Z','2026-06-20T02:42:05.902Z');
INSERT INTO misconfigurations VALUES('a858c3ce-266a-4741-8ad8-c6832e4a7316',1,'apache-httpd','LimitRequestFields','0','100','N','N','L','N','N','P',5.0,5.0,'M','H','[]','CCE-27741-8','10.2','Setting LimitRequestFields to 0 allows an unlimited number of request fields, which can be exploited by sending oversized requests that may exhaust server resources and cause performance degradation or denial-of-service conditions.','Set ''LimitRequestFields 100'' in the Apache configuration file.','value','always','','{"description": "The LimitRequestFields directive sets an upper limit on the number of request header fields that can be sent to the server. Setting this value to 0 allows unlimited request header fields, which can lead to resource exhaustion and denial-of-service attacks.", "potential_impact": ["Exhaust server resources", "Cause performance degradation", "Trigger a denial-of-service condition"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker sends an HTTP request with an excessive number of header fields to the Apache server. The request could look like this: GET / HTTP/1.1\r\nX-Test: value1\r\nX-Test: value2\r\n... (repeated many times)", "result": "The server''s resources are overwhelmed by handling and processing an excessive number of header fields, leading to performance degradation or a denial-of-service condition."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by sending oversized requests with numerous header fields without any special preconditions beyond making HTTP requests.", "c": "Why C=N: No sensitive information is disclosed or readable as a result of the attack.", "i": "Why I=N: The configuration and data on the server cannot be modified directly through this vulnerability.", "a": "Why A=P: Availability is significantly impacted due to resource exhaustion caused by handling excessive header fields.", "gel": "Why GEL=M: This type of misconfiguration can be exploited frequently as it allows for straightforward denial-of-service attacks.", "grl": "Why GRL=H: There are numerous resources and documentation available on how to properly configure LimitRequestFields."}}','2026-06-20T01:28:07.443Z','2026-06-20T02:44:10.584Z');
INSERT INTO misconfigurations VALUES('57ac05d1-da19-43b6-a4ad-73aeb562940c',1,'apache-httpd','LimitRequestFieldSize','0','8190','N','N','L','N','N','P',5.0,5.0,'M','H','[]','CCE-27554-5','10.3','Setting LimitRequestFieldSize to ''0'' allows any size of request headers, which can lead to resource exhaustion and degrade server performance but does not directly expose sensitive information or allow arbitrary code execution.','Set ''LimitRequestFieldsize 8190''.','value','always','','{"description": "The LimitRequestFieldSize directive restricts the size of request headers to prevent resource exhaustion attacks. Setting this value to ''0'' removes any limit on the size of request headers, allowing attackers to send excessively large requests and potentially causing server performance degradation or crashes.", "potential_impact": ["Degradation of server performance due to handling oversized request headers", "Resource exhaustion leading to denial-of-service conditions", "Increased risk of buffer overflow attacks if improperly handled by the server"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends a POST request with an extremely large Content-Length header, causing the server to allocate excessive memory and potentially crash.", "result": "The Apache HTTP Server becomes unresponsive or crashes due to resource exhaustion."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by sending oversized request headers without any special preconditions, making it trivially exploitable.", "c": "Why C=N: No sensitive information is directly disclosed or readable due to the misconfiguration.", "i": "Why I=N: The configuration itself cannot be modified through this vulnerability; however, server resources can be exhausted.", "a": "Why A=P: Availability of the Apache HTTP Server is significantly impacted as it may crash or become unresponsive under attack conditions.", "gel": "Why GEL=M: This type of misconfiguration has been observed in multiple instances and is known to be exploited by attackers seeking to disrupt service availability.", "grl": "Why GRL=H: There are numerous resources available for remediation, including official Apache documentation and security advisories."}}','2026-06-20T01:28:52.139Z','2026-06-20T02:46:18.967Z');
INSERT INTO misconfigurations VALUES('6bed243b-3852-4a0d-8705-49c2a39aad8e',1,'apache-httpd','LimitRequestBody','0','102400','N','N','L','N','N','P',5.0,5.0,'M','H','[]','CCE-27618-8','10.4','Unlimited request body size allows remote attackers to send large requests, potentially causing resource exhaustion and degrading service performance. This leads to a partial availability impact but does not result in full system compromise.','Set ''LimitRequestBody 102400'' or an appropriate value for your application''s needs.','value','always','','{"description": "The LimitRequestBody directive restricts the size of request bodies sent to the server. Setting this value to 0 removes any limit on request body sizes, allowing attackers to send arbitrarily large requests which can lead to resource exhaustion and denial-of-service conditions.", "potential_impact": ["Degradation of service performance", "Resource exhaustion leading to system unavailability", "Increased risk of server crashes due to excessive memory usage"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends a POST request with an extremely large body, such as:\nPOST / HTTP/1.1\nHost: example.com\nContent-Length: 50000000\ndata: very large payload", "result": "The server''s resources are overwhelmed by the large request, potentially causing it to crash or become unresponsive."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by sending a single oversized HTTP request without any special privileges or additional prerequisites.", "c": "Why C=N: No sensitive information is disclosed as the attack focuses on resource exhaustion rather than data exfiltration.", "i": "Why I=N: The configuration and data integrity are not directly compromised, but availability is impacted due to resource exhaustion.", "a": "Why A=P: Availability is partially affected because the server becomes unresponsive or crashes when handling large requests.", "gel": "Why GEL=M: This type of misconfiguration can be exploited with moderate frequency as it is a common oversight in web application security configurations.", "grl": "Why GRL=H: Remediation documentation and best practices for setting appropriate LimitRequestBody values are widely available."}}','2026-06-20T01:29:45.141Z','2026-06-20T02:48:30.090Z');
INSERT INTO misconfigurations VALUES('9d09ef10-1da5-4b6a-b1a8-cc6a689a0711',1,'apache-httpd','TraceEnable','On','Off','N','N','M','P','N','N',4.29999999999999982,4.29999999999999982,'M','H','["CVE-2004-2320", "CVE-2007-3008"]','CCE-27531-3','5.8','HTTP TRACE enables Cross-Site Tracing (XST) to steal cookies and other sensitive information, but requires a victim to visit a malicious page — AC is Medium. Impact is partial credential theft, not full system access.','Set ''TraceEnable Off'' in httpd.conf.','value','always','','{"description": "The TraceEnable directive in Apache HTTP Server allows clients to send TRACE requests which can be used for Cross-Site Tracing (XST) attacks. Setting it to ''On'' is dangerous because it enables attackers to steal cookies and other sensitive information from users.", "potential_impact": ["Steal session cookies and authentication tokens", "Perform Cross-Site Scripting (XSS) attacks by injecting malicious JavaScript code", "Expose internal network details through HTTP headers"], "exploitation_scenario": {"prerequisites": ["An attacker must诱使用户访问恶意网页或注入恶意脚本", "受害者必须点击包含恶意TRACE请求的链接或访问嵌入了恶意代码的页面"], "example": "A malicious user crafts a TRACE request to the server: OPTIONS / HTTP/1.1\r\nHost: example.com\r\nConnection: keep-alive\r\nUser-Agent: Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/89.0.4389.82 Safari/537.36", "result": "The server responds with the full request and response headers, including sensitive information such as cookies."}, "metric_justifications": {"ac": "Why AC=M: The attacker needs to诱使用户访问恶意网页或注入恶意脚本，这增加了攻击难度。", "c": "Why C=P: 敏感信息如会话cookie和认证令牌被泄露。", "i": "Why I=N: 服务器配置和数据本身不会被修改。", "a": "Why A=N: 可用性不受影响。", "gel": "Why GEL=M: 这种类型的误配置在实际攻击中较为常见，但不是非常频繁。", "grl": "Why GRL=H: 有广泛的文档和资源可用于修复此问题。"}}','2026-06-20T01:30:39.681Z','2026-06-20T02:51:01.844Z');
INSERT INTO misconfigurations VALUES('2ccb27df-819a-4e21-9f5f-88b35cca0ae0',1,'apache-httpd','Options','Indexes','None','N','N','L','P','N','N',5.0,5.0,'M','H','[]','CCE-27657-6','5.2','Enabling ''Indexes'' allows directory listings, which can disclose file structure and potentially sensitive information to remote attackers with a single HTTP request.','Set ''Options None'' or ''Options Multiviews'' in the web root <Directory> directive.','value','always','','{"description": "The ''Options Indexes'' directive allows directory listings to be displayed when a user requests a URL that corresponds to a directory. This can expose sensitive file structures and potentially reveal information about the server''s configuration or content.", "potential_impact": ["Discloses file structure", "Reveals sensitive files and directories", "Assists in reconnaissance for further attacks"], "exploitation_scenario": {"prerequisites": ["None"], "example": "A user sends an HTTP GET request to a directory URL, such as http://example.com/directory/. The server responds with a list of files and subdirectories within that directory.", "result": "The attacker gains visibility into the file structure of the web server, which can be used for further reconnaissance or exploitation."}, "metric_justifications": {"ac": "Why AC=L: Enabling ''Indexes'' allows any unauthenticated user to trigger a directory listing with a standard HTTP request, making it trivially exploitable.", "c": "Why C=P: The disclosure of file structure and potentially sensitive files can provide valuable information for an attacker to exploit other vulnerabilities or gain unauthorized access.", "i": "Why I=N: Directory listings do not allow modification of data or configuration directly through this feature alone, though they may aid in identifying targets for further attacks.", "a": "Why A=N: The availability of the web server is generally unaffected by directory listings; however, it can indirectly impact availability if attackers use the information to launch other types of attacks.", "gel": "Why GEL=M: Directory listing misconfigurations are commonly exploited as they provide easy reconnaissance opportunities for attackers.", "grl": "Why GRL=H: There is extensive documentation and guidance available on how to properly secure web server configurations, including disabling directory listings."}}','2026-06-20T01:31:20.963Z','2026-06-20T02:53:15.631Z');
INSERT INTO misconfigurations VALUES('04b497a9-e4b1-4873-b864-fd536fd685f2',1,'apache-httpd','Options','FollowSymLinks','SymLinksIfOwnerMatch','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','[]','CCE-27877-0','5.3','FollowSymLinks allows directory traversal via symlinks, but exploitation requires an attacker who already has write access to create the symlink — AC is Medium. Impact is limited to partial information disclosure and integrity modification within the web application scope.','Use ''Options SymLinksIfOwnerMatch'' instead of ''Options FollowSymLinks''.','value','always','','{"description": "The ''Options FollowSymLinks'' directive allows clients to access files via symbolic links within the web directory. This can lead to unauthorized file disclosure or modification if an attacker has write access to create malicious symlinks.", "potential_impact": ["Disclose sensitive information stored in linked directories", "Modify files and configurations through symlink attacks", "Compromise integrity of web application data"], "exploitation_scenario": {"prerequisites": ["An attacker must have write access to the web directory or a subdirectory where they can create symlinks", "The Apache server is configured with ''Options FollowSymLinks''"], "example": "Attacker creates a symlink in /var/www/html pointing to /etc/shadow and accesses it via HTTP request.", "result": "Sensitive system files are accessible through the web directory, leading to unauthorized information disclosure."}, "metric_justifications": {"ac": "Why AC=M: Exploitation requires an attacker with write access to create symlinks, which is a moderate barrier but not extremely difficult.", "c": "Why C=P: Partial information disclosure occurs as attackers can read files they should not have access to via symlinks.", "i": "Why I=P: Integrity of web application data and configuration files may be compromised through symlink attacks that allow file modification.", "a": "Why A=N: Availability is generally unaffected, but specific files or directories might become inaccessible if the attacker disrupts them.", "gel": "Why GEL=L: While symlink attacks are common, they require a specific set of conditions to exploit successfully, making it less frequent than other types of vulnerabilities.", "grl": "Why GRL=H: There is extensive documentation and guidance available on how to properly configure Apache to mitigate symlink risks."}}','2026-06-20T01:32:10.400Z','2026-06-20T02:55:30.548Z');
INSERT INTO misconfigurations VALUES('685174c9-4709-4ab9-818c-598891bfb8bf',1,'apache-httpd','Options','All','None','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','[]','CCE-27877-0','5.1','Options All allows full control over the root directory, enabling execution of CGI scripts and server-side includes. Exploitation requires write access to create malicious files or scripts — AC is Medium. Impact is limited to partial information disclosure and integrity compromise within the web application scope.','Set ''Options None'' for the root <Directory> element in httpd.conf.','value','always','','{"description": "The ''Options All'' directive in Apache HTTP Server enables all options for the specified directory, including execution of CGI scripts and server-side includes. This is dangerous because it allows attackers with write access to create malicious files or scripts that can be executed on the server.", "potential_impact": ["Discloses sensitive information through crafted requests", "Enables unauthorized modification of web application data", "Allows for remote code execution if a vulnerability exists in CGI scripts"], "exploitation_scenario": {"prerequisites": ["Write access to the web root directory or subdirectory", "Knowledge of how to exploit server-side includes or CGI scripts"], "example": "An attacker uploads a malicious .cgi file and triggers it via an HTTP request to execute arbitrary commands on the server.", "result": "The attacker gains unauthorized control over the web application, potentially leading to data theft, modification, or complete compromise of the system."}, "metric_justifications": {"ac": "Why AC=M: Exploitation requires write access to the directory and knowledge of how to exploit server-side includes or CGI scripts, creating a moderate barrier.", "c": "Why C=P: Sensitive information can be disclosed through crafted requests that trigger malicious files or scripts.", "i": "Why I=P: Web application data can be modified by uploading and executing malicious files or scripts.", "a": "Why A=N: Availability is not directly affected, but the web application may become unavailable if critical system resources are consumed or corrupted.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited as it requires specific conditions to be met by an attacker.", "grl": "Why GRL=H: There is extensive documentation and guidance available for securing Apache HTTP Server configurations."}}','2026-06-20T01:32:58.866Z','2026-06-20T02:57:41.842Z');
INSERT INTO misconfigurations VALUES('9e9e1973-907c-43cb-86d5-8f1e20513b67',1,'apache-httpd','AllowOverride','All','None','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','[]','CCE-27536-2','4.4','AllowOverride All allows .htaccess files to override server configuration, but exploitation requires an attacker who already has write access to the web root — AC is Medium. Impact is limited to partial information disclosure and integrity modification within the web application scope.','Set ''AllowOverride None'' globally; enable selectively only where required.','value','always','','{"description": "The AllowOverride directive controls which .htaccess file directives can override server configuration settings. Setting it to ''All'' allows any .htaccess file in a directory to modify Apache''s behavior, potentially leading to security vulnerabilities if an attacker gains write access to the web root.", "potential_impact": ["Discloses sensitive information through improperly configured .htaccess files", "Enables unauthorized modification of server configurations and permissions", "Allows execution of arbitrary code via misconfigured directives"], "exploitation_scenario": {"prerequisites": ["An attacker must have write access to the web root directory", "The attacker needs knowledge of how .htaccess files can be used to manipulate Apache settings"], "example": "Attacker uploads a malicious .htaccess file with directives like ''Options +ExecCGI'' and ''AddHandler cgi-script .pl'', allowing execution of arbitrary Perl scripts.", "result": "The attacker gains control over the web server''s configuration, potentially leading to full compromise of the application."}, "metric_justifications": {"ac": "Why AC=M: Exploitation requires an attacker with write access to the web root directory and knowledge of how .htaccess files can be used to manipulate Apache settings.", "c": "Why C=P: Sensitive information such as server configuration details or application-specific directives may be disclosed through improperly configured .htaccess files.", "i": "Why I=P: An attacker can modify server configurations, permissions, and execute arbitrary code via misconfigured .htaccess files, leading to partial integrity compromise within the web application scope.", "a": "Why A=N: Availability is not directly affected by this misconfiguration; however, it may indirectly impact availability if an attacker uses it to disrupt service or cause denial of service conditions.", "gel": "Why GEL=L: While exploitation requires specific preconditions (write access and knowledge), the frequency of successful attacks can be relatively low due to the need for these prerequisites.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure .htaccess files and mitigate risks associated with AllowOverride settings."}}','2026-06-20T01:33:48.663Z','2026-06-20T03:00:19.954Z');
INSERT INTO misconfigurations VALUES('f6e19a63-8581-4f55-a2fc-57db3674cd40',1,'apache-httpd','LoadModule','dav_module','#LoadModule dav_module','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','[]','CCE-27132-0','2.3','Enabling WebDAV modules exposes additional attack vectors for unauthorized file access and manipulation, but exploitation typically requires specific preconditions such as misconfigured access controls or local write access.','Comment out the ''LoadModule dav_module'' and ''LoadModule dav_fs_module'' directives in httpd.conf to disable WebDAV functionality.','value','always','','{"description": "The directive LoadModule dav_module enables the WebDAV module in Apache HTTP Server. Enabling this module can expose additional attack vectors for unauthorized file access and manipulation.", "potential_impact": ["Expose files to unauthorized read or write access", "Allow attackers to upload malicious scripts", "Enable directory traversal attacks"], "exploitation_scenario": {"prerequisites": ["Misconfigured access controls allowing write permissions", "Local network position for some types of attacks"], "example": "An attacker with local write access can use PUT requests to upload files. For example, a malicious user could send an HTTP request like: PUT /path/to/file.php HTTP/1.1 Host: target.example.com Content-Type: application/x-httpd-php", "result": "The attacker gains unauthorized control over the server''s file system and can modify or delete critical files."}, "metric_justifications": {"ac": "Why AC=M: Exploitation typically requires specific preconditions such as misconfigured access controls or local write access, making it moderately difficult.", "c": "Why C=P: Information disclosure occurs when attackers gain unauthorized read access to sensitive files and directories.", "i": "Why I=P: Attackers can modify or delete critical configuration files and scripts, leading to potential system compromise.", "a": "Why A=N: Availability is not directly affected unless the attacker uses WebDAV to disrupt services through file deletion or modification.", "gel": "Why GEL=L: Exploitation of this misconfiguration requires specific conditions that are less common in well-configured environments.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure and secure WebDAV functionality."}}','2026-06-20T01:34:37.466Z','2026-06-20T03:02:30.198Z');
INSERT INTO misconfigurations VALUES('26bc54ce-2427-4110-8d88-47acafd3e87f',1,'apache-httpd','LoadModule','status_module','#LoadModule status_module','N','N','L','P','N','N',5.0,5.0,'M','H','[]','CCE-27357-3','2.4','Enabling mod_status provides detailed server performance statistics, which can be used by attackers to refine their attacks based on the current load and configuration of the server.','Comment out or remove the ''LoadModule status_module modules/mod_status.so'' directive in httpd.conf.','value','always','','{"description": "The LoadModule directive is used to enable Apache modules. Enabling status_module provides detailed server performance statistics via the server-status page, which can be accessed by any user and reveals sensitive information about the server''s configuration and load.", "potential_impact": ["Discloses internal server details that could aid in further attacks", "Enables attackers to monitor server performance for timing attacks", "Provides insights into Apache configurations that may contain vulnerabilities"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends an HTTP request to /server-status and retrieves detailed information about the server''s current state.", "result": "The attacker gains visibility into the server''s performance metrics, module status, and other sensitive details."}, "metric_justifications": {"ac": "Why AC=L: The status_module can be trivially accessed via a standard HTTP request without any authentication or additional preconditions.", "c": "Why C=P: The module exposes critical information about the server''s configuration, performance metrics, and current state to unauthorized users.", "i": "Why I=N: While the module provides read-only access, it does not allow for modification of data or configuration files directly through this interface.", "a": "Why A=N: There is no direct impact on availability as the server-status page only provides information without affecting service delivery.", "gel": "Why GEL=M: Misconfigurations like exposing status_module are common and frequently exploited by attackers to gather intelligence.", "grl": "Why GRL=H: Remediation steps for disabling status_module are well-documented in Apache''s official documentation and security advisories."}}','2026-06-20T01:35:20.518Z','2026-06-20T03:04:33.145Z');
INSERT INTO misconfigurations VALUES('9fea5f74-7028-4bd7-a46d-28e476e3c57e',1,'apache-httpd','LoadModule','info_module','#LoadModule info_module','N','N','L','P','N','N',5.0,5.0,'M','H','[]','CCE-27852-3','2.8','Enabling the mod_info module allows attackers to access sensitive configuration information via /server-info, potentially exposing system paths, usernames/passwords, and database names.','Comment out or remove the ''LoadModule info_module modules/mod_info.so'' directive in httpd.conf.','value','always','','{"description": "The LoadModule directive enables Apache modules. Enabling info_module allows attackers to access detailed server configuration information via /server-info, which can expose sensitive data such as system paths and database credentials.", "potential_impact": ["Expose system paths", "Reveal usernames and passwords", "Disclose database names"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker sends an HTTP GET request to /server-info. The response contains detailed server configuration information.", "result": "The attacker gains access to sensitive configuration details that can be used for further attacks."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can easily exploit this misconfiguration by sending a standard HTTP request to /server-info, requiring no special privileges or preconditions.", "c": "Why C=P: The module discloses critical configuration details that could be used for further attacks, such as identifying system paths and database credentials.", "i": "Why I=N: While the information is sensitive, enabling info_module does not allow modification of data or configuration directly through this endpoint.", "a": "Why A=N: Enabling info_module does not inherently affect server availability; however, it can lead to information disclosure that may indirectly impact availability if used in conjunction with other attacks.", "gel": "Why GEL=M: Misconfigurations like enabling the info_module are moderately common and often exploited by attackers looking for detailed system information.", "grl": "Why GRL=H: There is extensive documentation available on how to remediate this misconfiguration, making it relatively easy to find guidance."}}','2026-06-20T01:36:02.201Z','2026-06-20T03:06:34.411Z');
INSERT INTO misconfigurations VALUES('64112972-2a3b-4039-a8c2-fd10a4536387',1,'apache-httpd','LoadModule','autoindex_module','#LoadModule autoindex_module','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','2.5','Enabling the autoindex module allows directory listings, revealing file and directory names which can aid attackers in understanding the server''s structure and identifying potential vulnerabilities.','Comment out or remove the ''LoadModule autoindex_module modules/mod_autoindex.so'' directive from httpd.conf to disable the mod_autoindex module.','value','always','','{"description": "The LoadModule directive enables Apache modules. Enabling autoindex_module allows directory listings to be displayed when a user requests a directory without an index file, revealing file and directory names which can aid attackers in understanding the server''s structure and identifying potential vulnerabilities.", "potential_impact": ["Discloses file and directory structures", "Aids reconnaissance efforts for further attacks", "Increases risk of information leakage"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker sends a request to a directory that does not have an index.html or similar default document. The server responds with a list of files and directories within the requested path.", "result": "The attacker gains visibility into the file structure, potentially identifying sensitive files or misconfigurations."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated user can easily trigger directory listings by requesting a directory without an index document. No special preconditions are required.", "c": "Why C=P: The module discloses file and directory names, providing valuable information to attackers for further reconnaissance or exploitation attempts.", "i": "Why I=N: Directory listing does not allow modification of data or configuration files directly through the autoindex_module itself.", "a": "Why A=N: Availability is not affected as the server continues to function normally while displaying directory listings.", "gel": "Why GEL=M: Misconfigurations allowing directory listings are common and frequently exploited by attackers for reconnaissance purposes.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure Apache to prevent directory listings."}}','2026-06-20T01:36:49.806Z','2026-06-20T03:08:34.063Z');
INSERT INTO misconfigurations VALUES('6f5046aa-144b-439e-928b-6e115732c1cd',1,'apache-httpd','LoadModule','userdir_module','#LoadModule userdir_module','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','CCE-27682-4','2.7','Enabling the UserDir module allows anonymous access to user home directories via HTTP requests, but exploitation requires an attacker to know specific usernames and paths — AC is Medium. This leads to partial information disclosure without full system compromise.','Comment out or remove the ''LoadModule userdir_module modules/mod_userdir.so'' directive in httpd.conf.','value','always','','{"description": "The LoadModule directive enables Apache modules. Enabling userdir_module allows anonymous access to user home directories via HTTP requests, which can lead to unauthorized information disclosure.", "potential_impact": ["Disclose sensitive files and directory structures", "Expose personal or development environments to the internet", "Reveal application configurations and source code"], "exploitation_scenario": {"prerequisites": ["Knowledge of specific usernames and paths on the server", "Access to a web browser or HTTP client"], "example": "An attacker can access user directories by making an HTTP request such as http://example.com/~username/", "result": "The attacker gains unauthorized read access to files within the specified user''s home directory."}, "metric_justifications": {"ac": "Why AC=M: Enabling userdir_module requires an attacker to know specific usernames and paths, creating a moderate barrier that is not trivial but also not highly complex.", "c": "Why C=P: Partial information disclosure occurs as sensitive files and directory structures are exposed without full system compromise.", "i": "Why I=N: No data or configuration can be modified directly through this misconfiguration alone.", "a": "Why A=N: Availability is not affected; the server remains operational but vulnerable to information leakage.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited as it requires specific knowledge and does not offer a direct path to system compromise.", "grl": "Why GRL=H: There are numerous resources available for remediation, including official Apache documentation and security guidelines."}}','2026-06-20T01:37:33.733Z','2026-06-20T03:10:33.565Z');
INSERT INTO misconfigurations VALUES('7b305930-3d9b-4a05-b220-71c3d3e0e32b',1,'apache-httpd','SSLProtocol','All','TLSv1.2 TLSv1.3','N','N','L','P','N','N',5.0,5.0,'M','H','["CVE-2011-3389"]','CCE-27740-0','7.4','Enabling TLSv1.0 and TLSv1.1 exposes the server to vulnerabilities like BEAST, which can lead to information disclosure via CBC mode ciphers. Modern browsers no longer support these protocols, making exploitation more likely.','Set ''SSLProtocol +TLSv1.2 +TLSv1.3'' in the Apache configuration file.','value','always','','{"description": "The SSLProtocol directive specifies which versions of SSL/TLS are enabled for secure connections. Setting it to ''All'' enables outdated and insecure protocols like TLSv1.0 and TLSv1.1, exposing the server to known vulnerabilities such as BEAST.", "potential_impact": ["Expose the server to information disclosure via CBC mode ciphers", "Allow attackers to exploit deprecated SSL/TLS versions for man-in-the-middle attacks", "Reduce security posture by enabling insecure cryptographic protocols"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker can send a specially crafted request using an outdated TLS version, such as TLSv1.0 or TLSv1.1, to exploit vulnerabilities like BEAST.", "result": "The server responds with encrypted data that the attacker can decrypt due to weaknesses in the deprecated protocols."}, "metric_justifications": {"ac": "Why AC=L: Any unauthenticated attacker can trigger this vulnerability by sending a standard HTTP request using an outdated TLS version, making exploitation trivial.", "c": "Why C=P: Confidentiality is partially impacted as attackers can exploit vulnerabilities in deprecated protocols to disclose sensitive information.", "i": "Why I=N: The misconfiguration does not allow for direct modification of data or configuration files on the server.", "a": "Why A=N: Availability is not directly affected by this misconfiguration, but it may indirectly impact service if exploited successfully.", "gel": "Why GEL=M: Exploitation frequency is moderate as attackers actively seek out and exploit servers with outdated TLS versions.", "grl": "Why GRL=H: There are numerous resources available for remediation of SSLProtocol misconfigurations, making it easy to find guidance on how to fix this issue."}}','2026-06-20T01:38:25.497Z','2026-06-20T03:12:49.305Z');
INSERT INTO misconfigurations VALUES('6acb5a79-889a-4284-86c3-1fc93742982e',1,'apache-httpd','SSLProtocol','+SSLv3','TLSv1.2 TLSv1.3','N','N','L','P','N','N',5.0,5.0,'M','H','["CVE-2014-3566"]','CCE-27740-0','7.4','Enabling SSLv3 exposes the server to vulnerabilities like POODLE, which can lead to plaintext information disclosure. Any remote attacker can exploit this with a single HTTP request.','Set ''SSLProtocol TLSv1.2 +TLSv1.3'' in httpd.conf.','value','always','','{"description": "The SSLProtocol directive specifies which SSL/TLS protocols are enabled for secure connections. Enabling +SSLv3 exposes the server to vulnerabilities such as POODLE, which can lead to plaintext information disclosure.", "potential_impact": ["Disclose sensitive data in plaintext", "Enable man-in-the-middle attacks", "Expose the server to known SSLv3 vulnerabilities"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends an HTTP request to a vulnerable endpoint that supports SSLv3, initiating a connection using this outdated protocol.", "result": "The attacker can exploit the POODLE vulnerability to decrypt sensitive information transmitted over the SSLv3 connection."}, "metric_justifications": {"ac": "Why AC=L: Enabling +SSLv3 exposes the server to vulnerabilities like POODLE, which can be exploited with a single HTTP request. No special preconditions are required beyond sending an ordinary request.", "c": "Why C=P: The attacker can read sensitive data in plaintext due to vulnerabilities such as POODLE.", "i": "Why I=N: There is no direct impact on the server''s configuration or data integrity from enabling SSLv3 alone.", "a": "Why A=N: Availability of services remains unaffected, but confidentiality and integrity are compromised.", "gel": "Why GEL=M: Exploitation of SSLv3 vulnerabilities like POODLE has been observed in the wild with moderate frequency.", "grl": "Why GRL=H: There is extensive documentation available on how to remediate SSLv3 support, including detailed guides and best practices."}}','2026-06-20T01:39:11.249Z','2026-06-20T03:14:52.571Z');
INSERT INTO misconfigurations VALUES('342ce316-5e69-4ce6-86bf-54f23b11d2b2',1,'apache-httpd','SSLCompression','On','Off','N','N','L','P','N','N',5.0,5.0,'M','H','["CVE-2012-4929"]','','7.7','Enabling SSL compression increases the risk of CRIME attacks, allowing an attacker to derive session cookie values and potentially impersonate users.','Set ''SSLCompression Off'' in the Apache configuration files.','value','always','','{"description": "The SSLCompression directive enables or disables compression for SSL/TLS connections. Setting it to ''On'' increases the risk of CRIME attacks, which can allow an attacker to derive session cookie values and potentially impersonate users.", "potential_impact": ["Disclose sensitive information such as session cookies", "Enable attackers to perform session hijacking", "Compromise user authentication and data integrity"], "exploitation_scenario": {"prerequisites": ["An attacker with the ability to intercept SSL/TLS traffic"], "example": "Attacker sends specially crafted requests to exploit compression-based attacks like CRIME, using statistical analysis of compressed data sizes.", "result": "The attacker successfully extracts session cookie values and can use them for unauthorized access."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can trigger this with a standard HTTP request, making it trivial to exploit once the vulnerability is known.", "c": "Why C=P: The attack allows an attacker to read sensitive information such as session cookies and other compressed data.", "i": "Why I=N: There is no direct impact on modifying server configuration or data due to this misconfiguration alone.", "a": "Why A=N: Availability of the service is not directly impacted by enabling SSL compression, though it may indirectly affect users through compromised sessions.", "gel": "Why GEL=M: This type of misconfiguration has been exploited in the past and remains a concern for systems with outdated configurations.", "grl": "Why GRL=H: There are numerous resources available online detailing how to remediate this issue, including official Apache documentation."}}','2026-06-20T01:39:50.187Z','2026-06-20T03:16:54.563Z');
INSERT INTO misconfigurations VALUES('d0bc2030-ccc8-44f3-97e3-9c231c5d3a99',1,'apache-httpd','User','root','apache','N','N','L','C','C','N',9.40000000000000035,9.40000000000000035,'M','H','[]','CCE-27756-6','3.1','Running Apache as the root user allows any web vulnerability to grant full system access, enabling attackers to compromise the entire server without further steps.','Set ''User apache'' and ''Group apache'' in httpd.conf to run Apache with a dedicated unprivileged account.','value','always','','{"description": "The User directive specifies which user account Apache runs under. Setting it to ''root'' allows Apache to execute all system commands and access any file on the server, significantly increasing the risk of a full system compromise if an attacker exploits a web vulnerability.", "potential_impact": ["Compromise the entire server", "Gain root privileges for the attacker", "Execute arbitrary code with elevated permissions"], "exploitation_scenario": {"prerequisites": ["An exploitable web application or Apache module"], "example": "An attacker sends a malicious request to an affected web application, triggering a vulnerability that allows them to execute commands as the root user.", "result": "The attacker gains full control over the server and can modify system configurations, steal sensitive data, or install backdoors."}, "metric_justifications": {"ac": "Why AC=L: Running Apache as ''root'' makes it trivial for an attacker to escalate privileges if any web application running under this configuration has a vulnerability. The attacker only needs to exploit the web application flaw.", "c": "Why C=C: An attacker can read or disclose sensitive system files and configurations, leading to potential data exfiltration or further exploitation.", "i": "Why I=C: With root privileges, an attacker can modify any file on the server, including critical system binaries and configuration files, potentially allowing for persistent backdoor installation.", "a": "Why A=N: The availability of services is not directly impacted by running Apache as ''root'', but the risk of service disruption or denial-of-service attacks increases due to compromised system integrity.", "gel": "Why GEL=M: Misconfigurations like running web servers with root privileges are common and frequently exploited, making this type of vulnerability a frequent target for attackers.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure Apache to run under a non-privileged user account, making it easy to find guidance on remediation."}}','2026-06-20T01:40:30.749Z','2026-06-20T03:19:18.851Z');
INSERT INTO misconfigurations VALUES('57b1c824-d59f-4531-bc27-1b3fee173f3c',1,'apache-httpd','Group','root','apache','N','N','L','P','C','N',8.5,8.5,'M','H','[]','CCE-27566-9','3.1','Running Apache with Group ''root'' allows any web vulnerability to grant full system access via group permissions, enabling attackers to modify critical system files and escalate privileges.','Set ''Group apache'' in the httpd.conf file.','value','always','','{"description": "The Group directive in Apache HTTP Server specifies the group under which the server runs. Setting ''Group root'' allows the web server to have full system access via group permissions, potentially enabling any web vulnerability to be exploited for privilege escalation.", "potential_impact": ["Allows an attacker to modify critical system files", "Enables unauthorized execution of commands with elevated privileges", "Facilitates further exploitation and lateral movement within the network"], "exploitation_scenario": {"prerequisites": ["An existing web application vulnerability"], "example": "An attacker exploits a known vulnerability in an Apache module or CGI script, gaining control over the server process. By leveraging the ''Group root'' setting, they can modify system files such as /etc/passwd to escalate privileges.", "result": "The attacker gains full administrative access to the system."}, "metric_justifications": {"ac": "Why AC=L: An attacker only needs a web application vulnerability and no additional permissions beyond sending an HTTP request, making it easy to exploit.", "c": "Why C=P: The configuration allows for disclosure of sensitive information through file access or command execution.", "i": "Why I=C: Full system modification is possible due to the ''Group root'' setting, allowing attackers to alter critical files and configurations.", "a": "Why A=N: Availability may be affected if the attacker disrupts services by modifying configuration files or deleting essential system binaries.", "gel": "Why GEL=M: Misconfigurations like running Apache with group ''root'' are frequently exploited due to their ease of use and high impact.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure the Group directive for security best practices."}}','2026-06-20T01:41:08.673Z','2026-06-20T03:21:30.354Z');
INSERT INTO misconfigurations VALUES('65bf23b2-d7d6-48b4-8e2a-26d0357b6637',1,'apache-httpd','LogLevel','emerg','warn','N','N','L','P','N','N',5.0,5.0,'M','H','[]','CCE-27879-6','6.1','Setting LogLevel to ''emerg'' severely restricts the logging of errors, making it difficult to detect and respond to potential security issues. This can allow attackers to exploit vulnerabilities without being detected.','Set ''LogLevel notice core:info'' to ensure that all critical errors are logged for monitoring and forensic analysis.','value','always','','{"description": "The LogLevel directive controls the verbosity of Apache HTTP Server logs. Setting LogLevel to ''emerg'' restricts logging to only the most critical errors, which can prevent detection and response to security incidents.", "potential_impact": ["Prevent detection of unauthorized access attempts", "Hinder forensic analysis by limiting error log entries", "Allow attackers to exploit vulnerabilities without being logged"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker sends a malicious request that would normally trigger an error in the logs. Since LogLevel is set to ''emerg'', no logging occurs, and the attack goes undetected.", "result": "The attacker can exploit vulnerabilities without being logged or detected."}, "metric_justifications": {"ac": "Why AC=L: Setting LogLevel to ''emerg'' makes it easy for attackers to exploit vulnerabilities without detection because no logging occurs, making the attack chain straightforward and requiring minimal effort.", "c": "Why C=P: The configuration itself is readable by anyone with access to the server''s configuration files, allowing them to identify this misconfiguration easily.", "i": "Why I=N: There is no direct impact on data or configuration modification due to the logging level alone; however, it indirectly enables other attacks that could modify data or configurations.", "a": "Why A=N: The availability of the service itself is not directly impacted by this misconfiguration. However, it can lead to indirect impacts if attackers exploit vulnerabilities without detection.", "gel": "Why GEL=M: Misconfigurations like setting LogLevel to ''emerg'' are common and frequently exploited due to their ease of discovery and exploitation.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure the LogLevel directive, making it easy for administrators to identify and remediate this issue."}}','2026-06-20T01:41:51.872Z','2026-06-20T03:23:45.975Z');
INSERT INTO misconfigurations VALUES('374e1073-ceaf-4370-858b-764765217475',1,'apache-httpd','Order','Allow,Deny','Deny,Allow','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','CCE-27510-7','4.1','Order ''Allow,Deny'' allows access to the OS root directory unless explicitly denied elsewhere. This requires an attacker to have write access or a specific network position to exploit it — AC is Medium. The impact is limited to partial information disclosure.','Use ''Require all denied'' in the root <Directory> element to enforce default deny policy.','value','always','','{"description": "The ''Order Allow,Deny'' directive in Apache HTTP Server allows access to all users by default and then selectively denies access based on subsequent rules. This misconfiguration can lead to unauthorized access if not properly managed, as it does not enforce a strict deny-first policy.", "potential_impact": ["Discloses partial information about the file system structure", "Enables unauthorized read access to sensitive files or directories", "Allows an attacker with write permissions to modify web content"], "exploitation_scenario": {"prerequisites": ["An attacker must have write access to the web root directory or a specific network position that allows them to upload malicious content.", "The attacker needs to identify files or directories that are not explicitly denied in other configuration directives."], "example": "A misconfigured .htaccess file with ''Order Allow,Deny'' can be exploited by an attacker who uploads a PHP script to the web root directory. The attacker then accesses this script via HTTP request.", "result": "The attacker gains unauthorized read access to sensitive files or directories and potentially executes arbitrary code on the server."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs write access to the web root directory or a specific network position, which adds an additional layer of difficulty compared to trivial exploitation. This moderate barrier aligns with Medium complexity.", "c": "Why C=P: The misconfiguration allows partial information disclosure about file system structure and sensitive files, but does not lead to full control over the server.", "i": "Why I=N: While write access can be achieved, there is no direct impact on data modification or configuration changes unless an attacker exploits additional vulnerabilities.", "a": "Why A=N: The availability of services is not directly impacted by this misconfiguration; however, it may indirectly affect service integrity if sensitive files are accessed or modified.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited in the wild as attackers often target more direct vulnerabilities for full control rather than partial information disclosure.", "grl": "Why GRL=H: There is extensive documentation and guidance available on how to properly configure Apache HTTP Server directives, including best practices for security."}}','2026-06-20T01:42:43.031Z','2026-06-20T03:26:29.390Z');
INSERT INTO misconfigurations VALUES('dc50f730-e90f-4cbe-a8a9-d52afc5be90b',1,'apache-httpd','SSLUseStapling','','SSLUseStapling On','N','N','M','P','N','N',0.0,0.0,'L','W','[]','','7.10','Without SSLUseStapling On, Apache does not perform OCSP stapling. Clients must contact the CA directly for revocation status, which leaks browsing activity to the CA, degrades performance, and can be suppressed if the OCSP responder is unavailable.','Add ''SSLUseStapling On'' and ''SSLStaplingCache shmcb:logs/ssl_staple_cache(512000)'' to the server-level configuration and every SSL-enabled VirtualHost.','absence','if_directive:SSLCertificateFile','','{"description": "The SSLUseStapling directive enables OCSP (Online Certificate Status Protocol) stapling in Apache. Without ''SSLUseStapling On'', clients must independently query CAs for certificate revocation status, leading to privacy leaks and potential performance degradation.", "potential_impact": ["Leak browsing activity to the CA", "Degrade client performance due to additional network requests", "Expose users to man-in-the-middle attacks if OCSP responder is unavailable"], "exploitation_scenario": {"prerequisites": ["An attacker must intercept traffic between a client and an Apache server", "The client''s browser must be configured to check for certificate revocation status"], "example": "Attacker monitors network traffic to identify requests made by the client to the CA for OCSP checks. Attacker uses this information to correlate user activity.", "result": "The attacker gains insight into which websites a user is visiting, potentially allowing them to track user behavior and target specific users with phishing attacks."}, "metric_justifications": {"ac": "AC=M: An attacker needs to be in a position to intercept network traffic between the client and CA for OCSP checks. This requires an active MITM (Man-In-The-Middle) attack, which is moderately difficult but feasible.", "c": "C=P: The information disclosed includes browsing activity patterns that can be used to infer user behavior and interests.", "i": "I=N: There are no direct modifications or data breaches as a result of the misconfiguration itself; however, indirect impacts on privacy and security exist.", "a": "A=N: Availability is not directly impacted by this misconfiguration. However, performance may degrade due to additional network requests for OCSP checks.", "gel": "GEL=L: While SSLUseStapling misconfigurations are common, they do not typically lead to widespread exploitation as the impact is primarily privacy-related and indirect.", "grl": "GRL=W: Remediation documentation is widely available in Apache''s official documentation and security guidelines."}}','2026-06-20T01:42:43.036Z','2026-06-20T03:29:01.750Z');
INSERT INTO misconfigurations VALUES('bebd1e7e-b8a6-461f-8c53-fb4cb102564a',1,'apache-httpd','Header','','Header always set Strict-Transport-Security "max-age=600; includeSubDomains"','N','N','M','P','P','N',0.0,0.0,'L','W','[]','','7.11','Without HSTS, browsers are not instructed to enforce HTTPS. This leaves users vulnerable to protocol downgrade attacks (sslstrip) and cookie hijacking on their first visit or after the HSTS policy expires.','Add ''Header always set Strict-Transport-Security "max-age=600; includeSubDomains"'' to every SSL-enabled VirtualHost.','absence','if_directive:SSLCertificateFile','Strict-Transport-Security','{"description": "The Header directive without a Permissions-Policy header allows web pages to access sensitive device features such as geolocation, microphone, and camera without explicit restrictions. This misconfiguration violates the principle of least privilege by potentially exposing users'' devices to unauthorized access.", "potential_impact": ["Expose user''s location data", "Allow unauthorized audio recording", "Enable unauthorized video capture"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can exploit this misconfiguration by crafting a web page that requests access to the user''s geolocation, microphone, and camera. The server responds without enforcing any restrictions.", "result": "The browser grants the web page unrestricted access to sensitive device features."}, "metric_justifications": {"ac": "Why AC=L: An attacker can exploit this misconfiguration by simply accessing a web page that requests permissions, making it trivially easy with no special preconditions beyond sending an HTTP request.", "c": "Why C=P: The information disclosed includes sensitive user data such as location and media content.", "i": "Why I=N: There is no direct impact on the server''s configuration or data integrity.", "a": "Why A=N: Availability of services is not affected, but user privacy may be compromised.", "gel": "Why GEL=L: This type of misconfiguration can be exploited frequently as it relies on default browser behavior without explicit restrictions.", "grl": "Why GRL=W: Remediation documentation for setting the Permissions-Policy header is widely available and well-documented."}}','2026-06-20T01:42:43.038Z','2026-06-20T03:37:36.903Z');
INSERT INTO misconfigurations VALUES('6e18490b-2467-4cc5-955c-3bbe62a7e61d',1,'apache-httpd','Header','','Header always append Content-Security-Policy "frame-ancestors ''self''"','N','N','L','P','P','N',0.0,0.0,'L','W','[]','','5.16','Without a Content-Security-Policy or X-Frame-Options header, Apache does not prevent clickjacking attacks where an attacker frames the site inside an iframe on a malicious page. UI redressing can trick users into performing unintended actions on the legitimate site.','Add ''Header always append Content-Security-Policy "frame-ancestors ''self''"'' to the server configuration.','absence','always','Content-Security-Policy','{"description": "The Header directive without a Permissions-Policy header allows web pages to access sensitive device features such as geolocation, microphone, and camera without explicit restrictions. This misconfiguration violates the principle of least privilege by potentially exposing users'' devices to unauthorized access.", "potential_impact": ["Expose user''s location data", "Allow unauthorized audio recording", "Enable unauthorized video capture"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can exploit this misconfiguration by crafting a web page that requests access to the user''s geolocation, microphone, and camera. The server responds without enforcing any restrictions.", "result": "The browser grants the web page unrestricted access to sensitive device features."}, "metric_justifications": {"ac": "Why AC=L: An attacker can exploit this misconfiguration by simply accessing a web page that requests permissions, making it trivially easy with no special preconditions beyond sending an HTTP request.", "c": "Why C=P: The information disclosed includes sensitive user data such as location and media content.", "i": "Why I=N: There is no direct impact on the server''s configuration or data integrity.", "a": "Why A=N: Availability of services is not affected, but user privacy may be compromised.", "gel": "Why GEL=L: This type of misconfiguration can be exploited frequently as it relies on default browser behavior without explicit restrictions.", "grl": "Why GRL=W: Remediation documentation for setting the Permissions-Policy header is widely available and well-documented."}}','2026-06-20T01:42:43.040Z','2026-06-20T03:37:36.903Z');
INSERT INTO misconfigurations VALUES('a5ce2711-6db4-46f6-a534-9fe99b40a410',1,'apache-httpd','Header','','Header set Referrer-Policy "strict-origin-when-cross-origin"','N','N','L','P','N','N',0.0,0.0,'L','W','[]','','5.17','Without an explicit Referrer-Policy header, browsers may send the full URL including sensitive query parameters (session tokens, PII) to third-party sites via the Referer header.','Add ''Header set Referrer-Policy "strict-origin-when-cross-origin"'' to the server configuration.','absence','always','Referrer-Policy','{"description": "The Header directive without a Permissions-Policy header allows web pages to access sensitive device features such as geolocation, microphone, and camera without explicit restrictions. This misconfiguration violates the principle of least privilege by potentially exposing users'' devices to unauthorized access.", "potential_impact": ["Expose user''s location data", "Allow unauthorized audio recording", "Enable unauthorized video capture"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can exploit this misconfiguration by crafting a web page that requests access to the user''s geolocation, microphone, and camera. The server responds without enforcing any restrictions.", "result": "The browser grants the web page unrestricted access to sensitive device features."}, "metric_justifications": {"ac": "Why AC=L: An attacker can exploit this misconfiguration by simply accessing a web page that requests permissions, making it trivially easy with no special preconditions beyond sending an HTTP request.", "c": "Why C=P: The information disclosed includes sensitive user data such as location and media content.", "i": "Why I=N: There is no direct impact on the server''s configuration or data integrity.", "a": "Why A=N: Availability of services is not affected, but user privacy may be compromised.", "gel": "Why GEL=L: This type of misconfiguration can be exploited frequently as it relies on default browser behavior without explicit restrictions.", "grl": "Why GRL=W: Remediation documentation for setting the Permissions-Policy header is widely available and well-documented."}}','2026-06-20T01:42:43.042Z','2026-06-20T03:37:36.903Z');
INSERT INTO misconfigurations VALUES('cd3aad2e-3ceb-4041-8073-d73aea8aa627',1,'apache-httpd','Header','','Header set Permissions-Policy "geolocation=(), microphone=(), camera=()"','N','N','L','P','N','N',0.0,0.0,'L','W','[]','','5.18','Without a Permissions-Policy header, browsers may allow web pages to access sensitive device features (geolocation, microphone, camera) without explicit restriction, violating the principle of least privilege.','Add ''Header set Permissions-Policy "geolocation=(), microphone=(), camera=()"'' to the server configuration, adjusted for the application''s actual needs.','absence','always','Permissions-Policy','{"description": "The Header directive without a Permissions-Policy header allows web pages to access sensitive device features such as geolocation, microphone, and camera without explicit restrictions. This misconfiguration violates the principle of least privilege by potentially exposing users'' devices to unauthorized access.", "potential_impact": ["Expose user''s location data", "Allow unauthorized audio recording", "Enable unauthorized video capture"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can exploit this misconfiguration by crafting a web page that requests access to the user''s geolocation, microphone, and camera. The server responds without enforcing any restrictions.", "result": "The browser grants the web page unrestricted access to sensitive device features."}, "metric_justifications": {"ac": "Why AC=L: An attacker can exploit this misconfiguration by simply accessing a web page that requests permissions, making it trivially easy with no special preconditions beyond sending an HTTP request.", "c": "Why C=P: The information disclosed includes sensitive user data such as location and media content.", "i": "Why I=N: There is no direct impact on the server''s configuration or data integrity.", "a": "Why A=N: Availability of services is not affected, but user privacy may be compromised.", "gel": "Why GEL=L: This type of misconfiguration can be exploited frequently as it relies on default browser behavior without explicit restrictions.", "grl": "Why GRL=W: Remediation documentation for setting the Permissions-Policy header is widely available and well-documented."}}','2026-06-20T01:42:43.045Z','2026-06-20T03:37:36.903Z');
INSERT INTO misconfigurations VALUES('01df25c0-aa24-49f8-8c04-cac2d531d15c',2,'nginx','server_tokens','on','off','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','2.5.1','ServerTokens on exposes the Apache version and OS in every HTTP response header, enabling attackers to conduct reconnaissance and target known vulnerabilities for the disclosed version.','Set ''server_tokens off'' to hide the server version and reduce attack surface.','value','always','','{"description": "The server_tokens directive in Nginx controls whether version information is included in HTTP responses. Setting it to ''on'' exposes detailed version and OS information which can be used by attackers for targeted attacks.", "potential_impact": ["Enables reconnaissance on the exact version of Nginx running, allowing attackers to identify known vulnerabilities specific to that version", "Increases risk of targeted exploitation based on disclosed version details", "Reduces overall security posture by providing unnecessary information to potential attackers"], "exploitation_scenario": {"prerequisites": ["An attacker with access to any HTTP request can exploit this misconfiguration."], "example": "Sending an OPTIONS or HEAD request to the server will reveal version details in the Server header.", "result": "The attacker gains detailed information about the Nginx version and OS, which can be used for further targeted attacks."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can easily discover the server version by sending a standard HTTP request such as OPTIONS or HEAD.", "c": "Why C=P: The configuration information is disclosed, allowing attackers to conduct targeted reconnaissance and exploit known vulnerabilities.", "i": "Why I=N: No sensitive data or configurations are directly modified through this misconfiguration alone.", "a": "Why A=N: Availability of the service itself is not impacted by exposing version information in headers.", "gel": "Why GEL=M: Misconfigurations like server_tokens=on are frequently exploited due to their ease and effectiveness in reconnaissance.", "grl": "Why GRL=H: There is extensive documentation available on how to remediate this issue, making it straightforward for administrators to fix."}}','2026-06-20T01:43:37.797Z','2026-06-20T03:39:44.636Z');
INSERT INTO misconfigurations VALUES('b335fba0-9275-4353-90b0-4c9637a99fda',2,'nginx','keepalive_timeout','65','10','N','N','L','N','N','P',5.0,5.0,'M','H','[]','','2.4.3','A high keep-alive timeout can lead to resource exhaustion and degraded performance as too many persistent connections may remain open, consuming server resources over an extended period.','Set ''keepalive_timeout'' to a value of 10 seconds or less, but not 0. For example: ''keepalive_timeout 10;''','value','always','','{"description": "The keepalive_timeout directive sets the duration in seconds that Nginx will wait for subsequent requests on an open connection before closing it. A value of 65 seconds is excessively high and can lead to resource exhaustion as too many persistent connections may remain open, consuming server resources over a prolonged period.", "potential_impact": ["Degraded performance due to excessive open connections", "Resource exhaustion leading to denial-of-service conditions", "Increased vulnerability to specific attacks exploiting long-lived connections"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker can exploit this misconfiguration by initiating a large number of keep-alive requests, causing the server to maintain these connections for up to 65 seconds. This can be done with standard HTTP requests.", "result": "The server''s resources are overwhelmed due to excessive open connections, leading to degraded performance and potential denial-of-service."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by sending a large number of keep-alive requests with standard HTTP methods, requiring no special preconditions beyond the ability to send HTTP requests.", "c": "Why C=N: No sensitive information is disclosed or readable as a result of this misconfiguration.", "i": "Why I=N: The configuration itself cannot be modified directly through exploitation; however, server resources can be consumed leading to indirect impact on other services.", "a": "Why A=P: Availability is significantly impacted due to resource exhaustion and degraded performance caused by excessive open connections.", "gel": "Why GEL=M: This type of misconfiguration is moderately common as administrators may not regularly review or adjust keepalive_timeout settings.", "grl": "Why GRL=H: There are numerous resources available for remediation, including official Nginx documentation and security guidelines."}}','2026-06-20T01:44:20.797Z','2026-06-20T03:42:03.561Z');
INSERT INTO misconfigurations VALUES('de2faeca-57c0-4826-9ec5-b07a91a716da',2,'nginx','keepalive_timeout','0','10','N','N','L','N','N','P',5.0,5.0,'M','H','[]','','2.4.3','Setting keepalive_timeout to ''0'' allows persistent connections to remain open indefinitely, potentially leading to resource exhaustion and denial of service attacks. However, the impact is gradual rather than immediate.','Set ''keepalive_timeout 10;'' or another value between 1-10 seconds.','value','always','','{"description": "The keepalive_timeout directive sets the duration in seconds that Nginx will wait for subsequent requests on an open connection before closing it. Setting this value to ''0'' disables the timeout entirely, allowing persistent connections to remain indefinitely and potentially leading to resource exhaustion.", "potential_impact": ["Exhaust server resources by maintaining large numbers of idle connections", "Enable denial-of-service attacks through resource starvation", "Impede legitimate users from accessing services due to limited connection slots"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can initiate a large number of HTTP requests with persistent keep-alive headers, maintaining connections indefinitely.", "result": "The server''s available connection slots are consumed by idle connections, preventing legitimate users from establishing new sessions."}, "metric_justifications": {"ac": "Setting the keepalive_timeout to ''0'' is easily exploitable as it requires only sending HTTP requests with persistent headers and maintaining those connections without further action.", "c": "No sensitive information is disclosed directly by this misconfiguration.", "i": "The configuration itself cannot be modified through this vulnerability, but server resources can be exhausted.", "a": "Availability is significantly impacted as the server''s ability to handle legitimate requests diminishes due to resource exhaustion.", "gel": "This type of misconfiguration is moderately likely to be exploited in environments where persistent connections are not properly managed.", "grl": "Remediation documentation for this issue is highly available, making it straightforward to correct."}}','2026-06-20T01:45:02.880Z','2026-06-20T03:43:57.487Z');
INSERT INTO misconfigurations VALUES('0f3ef6ed-98bf-41cd-8254-633631b75d1e',2,'nginx','send_timeout','0','10','N','N','L','N','N','P',5.0,5.0,'M','H','[]','','2.4.4','Setting send_timeout to ''0'' allows for indefinite write operations, enabling slow HTTP denial of service attacks that can degrade server performance gradually.','Set ''send_timeout 10;'' in the Apache configuration to mitigate slow HTTP DoS attacks.','value','always','','{"description": "The send_timeout directive specifies the number of seconds Nginx waits for a client to send another request body part or message header. Setting it to ''0'' disables this timeout entirely, allowing clients to perform slow HTTP denial-of-service attacks by sending requests at an arbitrarily slow pace.", "potential_impact": ["Degradation of server performance", "Resource exhaustion leading to service unavailability", "Increased latency for legitimate users"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends a request and deliberately pauses between sending each byte, ensuring the connection remains open without triggering any timeouts.", "result": "The server''s resources are gradually consumed by maintaining numerous idle connections, leading to denial of service for legitimate users."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily initiate a slow HTTP DoS attack with minimal effort and no special permissions required.", "c": "Why C=N: No sensitive information is disclosed as part of this misconfiguration.", "i": "Why I=N: The configuration itself cannot be modified by an attacker through this vulnerability.", "a": "Why A=P: Availability is significantly impacted due to resource exhaustion caused by slow HTTP DoS attacks.", "gel": "Why GEL=M: This type of misconfiguration can lead to frequent exploitation as it is well-known and easy to execute.", "grl": "Why GRL=H: There are numerous resources available for understanding and mitigating the risks associated with send_timeout misconfigurations."}}','2026-06-20T01:45:42.248Z','2026-06-20T03:45:53.416Z');
INSERT INTO misconfigurations VALUES('ffbd7a9d-f0bf-472d-b93d-203d6ce44fcb',2,'nginx','client_max_body_size','0','100k','N','N','L','N','N','P',5.0,5.0,'M','H','[]','','5.2.2','Setting client_max_body_size to ''0'' immediately rejects all requests with a 413 error, preventing any legitimate user actions that require form submissions or file uploads. This can be exploited by attackers to cause resource exhaustion and degrade service availability.','Set ''client_max_body_size'' to an appropriate value based on application requirements, such as ''2M'', and override it for specific endpoints if necessary.','value','always','','{"description": "The directive client_max_body_size sets an upper limit on the size of request bodies that Nginx will accept. Setting this value to ''0'' immediately rejects all requests with a 413 error, which can be exploited by attackers to cause resource exhaustion and degrade service availability.", "potential_impact": ["Deny legitimate user actions requiring form submissions or file uploads", "Cause resource exhaustion through repeated attempts to trigger the 413 error", "Degrade service availability for all users"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker sends a series of HTTP requests with varying body sizes, triggering Nginx''s client_max_body_size=0 and causing it to respond with 413 errors.", "result": "The server resources are consumed by handling these erroneous requests, leading to denial-of-service for legitimate users."}, "metric_justifications": {"ac": "Why AC=L: Setting client_max_body_size to ''0'' makes the service immediately vulnerable to resource exhaustion attacks as any unauthenticated attacker can trigger this with a standard HTTP request.", "c": "Why C=N: No sensitive information is disclosed or readable due to the 413 error response.", "i": "Why I=N: The configuration cannot be modified by attackers since no write access is required to exploit this misconfiguration.", "a": "Why A=P: Availability is significantly impacted as legitimate users are denied service and server resources may become exhausted from handling erroneous requests.", "gel": "Why GEL=M: This type of misconfiguration can occur frequently due to oversight or misunderstanding of the directive''s impact.", "grl": "Why GRL=H: Remediation documentation for this issue is widely available, making it easy to correct once identified."}}','2026-06-20T01:46:34.512Z','2026-06-20T03:48:07.405Z');
INSERT INTO misconfigurations VALUES('1264f888-7d71-4d72-a4c1-d37e166681a2',2,'nginx','ssl_protocols','TLSv1 TLSv1.1','TLSv1.2 TLSv1.3','N','N','L','P','N','N',5.0,5.0,'M','H','["CVE-2014-3566", "CVE-2016-2107"]','','4.1.4','Enabling legacy TLS protocols (TLSv1 and TLSv1.1) exposes the server to known vulnerabilities such as POODLE and other attacks that exploit weaknesses in these older versions, allowing attackers to potentially steal sensitive data.','Set ''ssl_protocols TLSv1.3'' to use only modern and secure protocols.','value','always','','{"description": "The ssl_protocols directive specifies which TLS versions are supported by Nginx. Configuring it to use TLSv1 and TLSv1.1 exposes the server to vulnerabilities such as POODLE and other attacks that exploit weaknesses in these older protocols, potentially allowing attackers to steal sensitive data.", "potential_impact": ["Allows an attacker to perform a downgrade attack using known vulnerabilities like POODLE", "Enables exploitation of weaknesses in TLSv1 and TLSv1.1 for man-in-the-middle (MITM) attacks", "Increases the risk of session hijacking due to outdated encryption methods"], "exploitation_scenario": {"prerequisites": ["An attacker with network access between client and server"], "example": "Client requests a connection using TLSv1. An attacker intercepts this request, forcing a downgrade to SSLv3 or an earlier version, then uses the POODLE vulnerability to decrypt session cookies.", "result": "The attacker successfully steals sensitive data such as session tokens and can use them for unauthorized access."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker with network access between client and server can easily exploit vulnerabilities in TLSv1 and TLSv1.1, such as POODLE, without needing any special privileges or additional preconditions.", "c": "Why C=P: Confidentiality is partially compromised due to the ability of attackers to intercept and decrypt sensitive data transmitted over insecure connections.", "i": "Why I=N: The misconfiguration does not allow for modification of server-side configurations or data, but it can lead to unauthorized access through stolen credentials.", "a": "Why A=N: Availability is not directly impacted by this misconfiguration; however, successful exploitation could indirectly affect availability if services are compromised and taken offline.", "gel": "Why GEL=M: This type of misconfiguration has been exploited moderately frequently due to the widespread use of older TLS versions before they were deprecated.", "grl": "Why GRL=H: There is extensive documentation available on how to remediate this issue, including detailed guides and best practices from security organizations."}}','2026-06-20T01:47:31.502Z','2026-06-20T03:50:47.407Z');
INSERT INTO misconfigurations VALUES('abd678e9-8ab4-4531-83ae-a67726a50579',2,'nginx','ssl_protocols','SSLv3','TLSv1.2 TLSv1.3','N','N','L','P','N','N',5.0,5.0,'H','H','["CVE-2014-3566"]','','4.1.4','Enabling SSLv3 exposes the POODLE vulnerability, allowing attackers to exploit weaknesses in CBC encryption and obtain cleartext information. This is actively exploited in the wild.','Set ''ssl_protocols TLSv1.3'' to ensure only modern and secure protocols are used.','value','always','','{"description": "The ssl_protocols directive specifies which SSL/TLS protocols are enabled for secure connections. Enabling SSLv3 exposes the POODLE vulnerability, allowing attackers to exploit weaknesses in CBC encryption and obtain cleartext information.", "potential_impact": ["Disclose sensitive data through the POODLE attack", "Enable man-in-the-middle attacks by downgrading TLS to SSLv3", "Expose server to known vulnerabilities associated with SSLv3"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends a specially crafted request to the server using SSLv3, initiating the POODLE attack.", "result": "The attacker can decrypt sensitive information transmitted over SSLv3 connections."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can trigger this with a standard HTTP request, making it trivial to exploit.", "c": "Why C=P: Confidentiality is partially compromised as the POODLE attack allows an attacker to decrypt sensitive data transmitted over SSLv3 connections.", "i": "Why I=N: Integrity is not directly impacted since no modifications can be made to the server''s configuration or data through this vulnerability alone.", "a": "Why A=N: Availability is not affected as the POODLE attack does not disrupt service availability, but it compromises confidentiality and integrity.", "gel": "Why GEL=H: The POODLE vulnerability is actively exploited in the wild due to its simplicity and effectiveness against SSLv3.", "grl": "Why GRL=H: There are extensive remediation guides available for disabling SSLv3 and enabling more secure protocols."}}','2026-06-20T01:48:19.672Z','2026-06-20T03:52:51.688Z');
INSERT INTO misconfigurations VALUES('e3becc61-4541-452d-875f-41c50f5c8d72',2,'nginx','ssl_session_tickets','off','on (or remove directive — default is on)','N','N','L','N','N','P',5.0,5.0,'M','H','[]','','4.1.11','Disabling ssl_session_tickets in TLS 1.3 reduces performance by increasing handshake latency, but does not expose any sensitive information or allow direct attacks.','Ensure that the directive ''ssl_session_tickets'' is either removed or set to ''on''.','value','always','','{"description": "The ssl_session_tickets directive enables or disables session tickets in TLS 1.3 for resuming sessions without full handshakes. Disabling it with ''off'' reduces performance and increases handshake latency.", "potential_impact": ["Increases the overhead of establishing new connections due to lack of session resumption", "Reduces overall system performance by requiring more frequent full TLS handshakes"], "exploitation_scenario": {"prerequisites": [], "example": "A client connects to a server with ssl_session_tickets off and initiates multiple HTTPS requests. Each request requires a new full TLS handshake.", "result": "The server experiences increased CPU load and higher latency due to repeated full handshakes."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily observe the performance degradation without needing any special permissions or conditions beyond making HTTP requests.", "c": "Why C=N: No sensitive information is disclosed as a result of disabling ssl_session_tickets.", "i": "Why I=N: The configuration cannot be modified by an attacker due to lack of disclosure or exploitable vulnerabilities.", "a": "Why A=P: Availability is impacted because the server must perform full TLS handshakes for each connection, leading to increased latency and potential performance degradation.", "gel": "Why GEL=M: This misconfiguration can occur frequently in environments where security configurations are not properly reviewed or updated.", "grl": "Why GRL=H: There is extensive documentation available on how to configure Nginx correctly for TLS 1.3, making remediation straightforward."}}','2026-06-20T01:48:57.076Z','2026-06-20T03:54:49.332Z');
INSERT INTO misconfigurations VALUES('99ca918a-1052-4793-94a9-d1d3012d0435',2,'nginx','proxy_pass','http://127.0.0.1:8080','https://backend with restrictions','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','2.5.4','Not stripping sensitive headers like X-Powered-By and Server allows attackers to gather information about the backend infrastructure, enabling targeted attacks based on known vulnerabilities.','Add ''proxy_hide_header X-Powered-By;'' and ''proxy_hide_header Server;'' in the NGINX configuration to prevent disclosure of sensitive information.','value','always','','{"description": "The directive proxy_pass is used to forward client requests to another server. Using http://127.0.0.1:8080 exposes internal backend services directly without proper security measures like encryption or header stripping, making it vulnerable to information disclosure and targeted attacks.", "potential_impact": ["Expose sensitive headers such as X-Powered-By and Server", "Allow attackers to gather detailed information about the backend infrastructure", "Enable targeted attacks based on known vulnerabilities of exposed services"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends a standard HTTP request to the Nginx server, which forwards it internally to http://127.0.0.1:8080 without stripping sensitive headers.", "result": "The attacker receives detailed information about the backend infrastructure and can use this data for targeted attacks."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can easily exploit this misconfiguration by sending a standard HTTP request to trigger the exposure of sensitive headers.", "c": "Why C=P: The configuration allows an attacker to read and gather detailed information about the backend infrastructure, including version numbers and technologies used.", "i": "Why I=N: There is no direct impact on data or configuration modification through this misconfiguration alone.", "a": "Why A=N: Availability of services is not directly affected by this misconfiguration.", "gel": "Why GEL=M: This type of misconfiguration can be exploited frequently as it exposes sensitive information that attackers can use for targeted attacks.", "grl": "Why GRL=H: There are numerous resources and documentation available to remediate such misconfigurations, making the risk high."}}','2026-06-20T01:49:46.671Z','2026-06-20T03:57:02.361Z');
INSERT INTO misconfigurations VALUES('23333440-2ecf-4795-abad-270448009d49',2,'nginx','proxy_ssl_verify','','proxy_ssl_verify on;','N','N','M','P','P','N',0.0,0.0,'L','W','[]','','4.1.10','Without proxy_ssl_verify on, NGINX does not validate the upstream server''s TLS certificate. This is equivalent to a browser ignoring all certificate warnings, making the proxy-to-backend channel vulnerable to man-in-the-middle attacks within the internal network.','Add ''proxy_ssl_verify on;'' to location blocks that use proxy_pass. Also configure proxy_ssl_trusted_certificate and proxy_ssl_name.','absence','if_directive:proxy_pass','','{"description": "The directive proxy_ssl_verify is used to enable TLS certificate verification for proxied requests. Without this directive set to ''on'', Nginx does not validate the upstream server''s TLS certificate, making it vulnerable to man-in-the-middle attacks within the internal network.", "potential_impact": ["Expose sensitive data in transit", "Allow attackers to intercept and modify traffic between Nginx and backend servers", "Compromise integrity of communications by injecting malicious content"], "exploitation_scenario": {"prerequisites": ["An attacker must be positioned within the internal network to perform a man-in-the-middle attack", "The attacker needs to have some level of control over the network infrastructure or be able to inject traffic between Nginx and backend servers"], "example": "Attacker uses ARP spoofing to intercept traffic between Nginx and backend server, then modifies requests or responses in transit.", "result": "The attacker can read, modify, or inject data into the communication channel between Nginx and the backend server."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs to be positioned within the internal network and have some level of control over the network infrastructure, which presents a moderate barrier.", "c": "Why C=P: Sensitive data in transit can be exposed and read by an attacker.", "i": "Why I=P: The integrity of communications can be compromised as attackers can modify or inject malicious content into traffic between Nginx and backend servers.", "a": "Why A=N: Availability is not directly affected, but the reliability of data transmission may be compromised due to tampering.", "gel": "Why GEL=L: While exploitation requires specific conditions within an internal network, it remains a relatively low-frequency event compared to external attacks.", "grl": "Why GRL=W: Remediation documentation is widely available and straightforward to implement."}}','2026-06-20T01:49:46.676Z','2026-06-20T03:59:24.344Z');
INSERT INTO misconfigurations VALUES('c3fff043-48f4-423b-b330-78d1227dc39f',2,'nginx','proxy_ssl_trusted_certificate','','proxy_ssl_trusted_certificate /etc/nginx/ssl/upstream_ca.crt;','N','N','M','P','P','N',0.0,0.0,'L','W','[]','','4.1.10','Without proxy_ssl_trusted_certificate, NGINX cannot verify the upstream server''s certificate against a trusted CA even when proxy_ssl_verify is on, leaving the mTLS chain incomplete.','Add ''proxy_ssl_trusted_certificate /path/to/ca.crt;'' to location blocks that use proxy_pass with upstream TLS.','absence','if_directive:proxy_pass','','{"description": "The directive proxy_ssl_trusted_certificate is used to specify the path to a file containing trusted CA certificates for verifying the SSL/TLS certificate of an upstream server. Without this directive set, Nginx cannot verify the identity of the upstream server even if proxy_ssl_verify is enabled, leading to potential man-in-the-middle attacks.", "potential_impact": ["Expose sensitive data over untrusted connections", "Allow attackers to intercept and modify traffic between Nginx and the backend server", "Compromise integrity of TLS communication"], "exploitation_scenario": {"prerequisites": ["An attacker must be able to perform a man-in-the-middle attack on the connection between Nginx and the upstream server.", "The attacker needs to have control over the network path where the traffic flows."], "example": "An attacker intercepts the SSL/TLS handshake between Nginx and an upstream server, presenting their own certificate. Since proxy_ssl_trusted_certificate is not set, Nginx does not verify the certificate against a trusted CA.", "result": "The attacker can successfully establish a TLS connection with Nginx, allowing them to intercept and modify all traffic between Nginx and the backend server."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs to be positioned in the network path where they can perform a man-in-the-middle attack. This requires some level of control over the network, making it moderately difficult but not impossible.", "c": "Why C=P: The attacker can read and potentially modify sensitive data transmitted between Nginx and the backend server.", "i": "Why I=P: The attacker can inject malicious content into the communication stream, leading to potential data corruption or injection attacks.", "a": "Why A=N: Availability is not directly impacted as the service remains operational; however, it may be compromised through data tampering.", "gel": "Why GEL=L: While a man-in-the-middle attack requires specific conditions and skills, such attacks are relatively common in targeted scenarios where attackers have network control.", "grl": "Why GRL=W: There is extensive documentation available on how to properly configure proxy_ssl_trusted_certificate for securing TLS connections."}}','2026-06-20T01:49:46.678Z','2026-06-20T04:02:08.598Z');
INSERT INTO misconfigurations VALUES('0674b54f-adfd-469c-a17f-59c55d09f1e5',2,'nginx','proxy_ssl_name','','proxy_ssl_name your-upstream-hostname.com;','N','N','M','P','P','N',0.0,0.0,'L','W','[]','','4.1.10','Without proxy_ssl_name, NGINX does not verify that the upstream server''s certificate Subject Name matches the expected hostname, allowing certificate substitution attacks even with proxy_ssl_verify on.','Add ''proxy_ssl_name your-upstream-hostname.com;'' to location blocks that use proxy_pass. The value must match the upstream server''s hostname.','absence','if_directive:proxy_pass','','{"description": "The directive proxy_ssl_name is used to specify the expected hostname of the upstream server for SSL verification. Without this directive, Nginx does not verify that the upstream server''s certificate Subject Name matches the expected hostname, allowing potential man-in-the-middle attacks even if proxy_ssl_verify is enabled.", "potential_impact": ["Expose sensitive data over an insecure connection", "Allow attackers to intercept and modify traffic between Nginx and the backend server", "Enable unauthorized access to backend services through certificate substitution"], "exploitation_scenario": {"prerequisites": ["An attacker must be able to perform a man-in-the-middle attack on the network"], "example": "Attacker performs a DNS spoofing attack, redirecting traffic intended for your-upstream-hostname.com to an attacker-controlled server with a valid but incorrect certificate. Nginx forwards requests without verifying the hostname.", "result": "The attacker can intercept and modify all data exchanged between Nginx and the backend server."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs to perform a man-in-the-middle attack, which requires network-level access or control over DNS resolution. This is not trivial but also not extremely difficult for an experienced attacker.", "c": "Why C=P: The confidentiality of data exchanged between Nginx and the backend server can be compromised, leading to exposure of sensitive information.", "i": "Why I=P: An attacker can modify or inject malicious content into requests forwarded by Nginx, potentially altering application behavior or causing service disruptions.", "a": "Why A=N: Availability is not directly impacted as the service remains operational. However, data integrity and confidentiality are compromised.", "gel": "Why GEL=L: While certificate substitution attacks can be sophisticated, they occur with some frequency in environments where proper SSL verification is neglected.", "grl": "Why GRL=W: There is extensive documentation available on how to properly configure proxy_ssl_name for secure communication between Nginx and backend servers."}}','2026-06-20T01:49:46.680Z','2026-06-20T04:04:36.243Z');
INSERT INTO misconfigurations VALUES('632a46c4-a052-4b55-ac31-f764822e85a4',2,'nginx','add_header','','add_header Strict-Transport-Security "max-age=63072000; includeSubDomains" always;','N','N','M','P','P','N',0.0,0.0,'L','W','[]','','4.1.8','Without the Strict-Transport-Security (HSTS) header, browsers are not instructed to enforce HTTPS. This leaves users vulnerable to protocol downgrade attacks and cookie hijacking on their first visit, before any HTTPS redirect has been applied.','Add ''add_header Strict-Transport-Security "max-age=63072000; includeSubDomains" always;'' to the server block serving HTTPS.','absence','if_directive:ssl_certificate','Strict-Transport-Security','{"description": "The directive ''add_header Referrer-Policy'' is used to set the HTTP header that controls how referrer information is sent when a user visits a site. Without specifying this policy, browsers may send sensitive data such as session tokens or personal information in the Referer header.", "potential_impact": ["Discloses session tokens and other sensitive information", "Exposes personal identifiable information (PII) to third-party sites", "Increases risk of tracking by malicious actors"], "exploitation_scenario": {"prerequisites": ["None"], "example": "A user visits a website that does not specify a Referrer-Policy. The browser sends the full URL, including session tokens and other sensitive data, to a third-party site as part of the Referer header.", "result": "The third-party site receives the sensitive information from the Referer header."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by simply visiting a website that does not specify a Referrer-Policy, which is trivially exploitable.", "c": "Why C=P: The configuration allows sensitive information such as session tokens and PII to be disclosed in the Referer header.", "i": "Why I=N: There is no direct impact on data or configuration modification due to this misconfiguration.", "a": "Why A=N: Availability of services is not affected by this misconfiguration.", "gel": "Why GEL=L: This type of misconfiguration can be exploited frequently as it relies on default browser behavior without explicit policy enforcement.", "grl": "Why GRL=W: Remediation documentation for setting the Referrer-Policy header is widely available and well-documented."}}','2026-06-20T01:49:46.682Z','2026-06-20T04:13:35.930Z');
INSERT INTO misconfigurations VALUES('cd5a041a-dc20-485e-8938-96551fcb518a',2,'nginx','add_header','','add_header X-Content-Type-Options "nosniff" always;','N','N','L','P','N','N',0.0,0.0,'L','W','[]','','5.3.1','Without X-Content-Type-Options: nosniff, browsers may perform MIME type sniffing and execute files as a different content type than declared. This enables drive-by download attacks and MIME confusion attacks where a text file is executed as a script.','Add ''add_header X-Content-Type-Options "nosniff" always;'' to the server block.','absence','always','X-Content-Type-Options','{"description": "The directive ''add_header Referrer-Policy'' is used to set the HTTP header that controls how referrer information is sent when a user visits a site. Without specifying this policy, browsers may send sensitive data such as session tokens or personal information in the Referer header.", "potential_impact": ["Discloses session tokens and other sensitive information", "Exposes personal identifiable information (PII) to third-party sites", "Increases risk of tracking by malicious actors"], "exploitation_scenario": {"prerequisites": ["None"], "example": "A user visits a website that does not specify a Referrer-Policy. The browser sends the full URL, including session tokens and other sensitive data, to a third-party site as part of the Referer header.", "result": "The third-party site receives the sensitive information from the Referer header."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by simply visiting a website that does not specify a Referrer-Policy, which is trivially exploitable.", "c": "Why C=P: The configuration allows sensitive information such as session tokens and PII to be disclosed in the Referer header.", "i": "Why I=N: There is no direct impact on data or configuration modification due to this misconfiguration.", "a": "Why A=N: Availability of services is not affected by this misconfiguration.", "gel": "Why GEL=L: This type of misconfiguration can be exploited frequently as it relies on default browser behavior without explicit policy enforcement.", "grl": "Why GRL=W: Remediation documentation for setting the Referrer-Policy header is widely available and well-documented."}}','2026-06-20T01:49:46.684Z','2026-06-20T04:13:35.930Z');
INSERT INTO misconfigurations VALUES('98d7b150-444b-43ae-b744-588d6a964190',2,'nginx','add_header','','add_header Content-Security-Policy "default-src ''self''; frame-ancestors ''self'';" always;','N','N','L','P','P','N',0.0,0.0,'L','W','[]','','5.3.2','Without a Content-Security-Policy header, browsers apply only the Same-Origin Policy, which does not prevent XSS attacks from loading external scripts or data exfiltration. CSP significantly reduces the XSS attack surface by whitelisting approved content sources.','Add a Content-Security-Policy header tailored to the application. Start with ''Content-Security-Policy-Report-Only'' to audit before enforcing. Minimum: default-src ''self''; frame-ancestors ''self''.','absence','always','Content-Security-Policy','{"description": "The directive ''add_header Referrer-Policy'' is used to set the HTTP header that controls how referrer information is sent when a user visits a site. Without specifying this policy, browsers may send sensitive data such as session tokens or personal information in the Referer header.", "potential_impact": ["Discloses session tokens and other sensitive information", "Exposes personal identifiable information (PII) to third-party sites", "Increases risk of tracking by malicious actors"], "exploitation_scenario": {"prerequisites": ["None"], "example": "A user visits a website that does not specify a Referrer-Policy. The browser sends the full URL, including session tokens and other sensitive data, to a third-party site as part of the Referer header.", "result": "The third-party site receives the sensitive information from the Referer header."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by simply visiting a website that does not specify a Referrer-Policy, which is trivially exploitable.", "c": "Why C=P: The configuration allows sensitive information such as session tokens and PII to be disclosed in the Referer header.", "i": "Why I=N: There is no direct impact on data or configuration modification due to this misconfiguration.", "a": "Why A=N: Availability of services is not affected by this misconfiguration.", "gel": "Why GEL=L: This type of misconfiguration can be exploited frequently as it relies on default browser behavior without explicit policy enforcement.", "grl": "Why GRL=W: Remediation documentation for setting the Referrer-Policy header is widely available and well-documented."}}','2026-06-20T01:49:46.685Z','2026-06-20T04:13:35.930Z');
INSERT INTO misconfigurations VALUES('afed1911-148f-4697-9520-814c7d5e2231',2,'nginx','add_header','','add_header Referrer-Policy "strict-origin-when-cross-origin" always;','N','N','L','P','N','N',0.0,0.0,'L','W','[]','','5.3.3','Without an explicit Referrer-Policy, browsers fall back to their defaults which may send the full URL (including query parameters with session tokens or PII) to third-party sites as the Referer header.','Add ''add_header Referrer-Policy "strict-origin-when-cross-origin" always;'' to the server block.','absence','always','Referrer-Policy','{"description": "The directive ''add_header Referrer-Policy'' is used to set the HTTP header that controls how referrer information is sent when a user visits a site. Without specifying this policy, browsers may send sensitive data such as session tokens or personal information in the Referer header.", "potential_impact": ["Discloses session tokens and other sensitive information", "Exposes personal identifiable information (PII) to third-party sites", "Increases risk of tracking by malicious actors"], "exploitation_scenario": {"prerequisites": ["None"], "example": "A user visits a website that does not specify a Referrer-Policy. The browser sends the full URL, including session tokens and other sensitive data, to a third-party site as part of the Referer header.", "result": "The third-party site receives the sensitive information from the Referer header."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by simply visiting a website that does not specify a Referrer-Policy, which is trivially exploitable.", "c": "Why C=P: The configuration allows sensitive information such as session tokens and PII to be disclosed in the Referer header.", "i": "Why I=N: There is no direct impact on data or configuration modification due to this misconfiguration.", "a": "Why A=N: Availability of services is not affected by this misconfiguration.", "gel": "Why GEL=L: This type of misconfiguration can be exploited frequently as it relies on default browser behavior without explicit policy enforcement.", "grl": "Why GRL=W: Remediation documentation for setting the Referrer-Policy header is widely available and well-documented."}}','2026-06-20T01:49:46.687Z','2026-06-20T04:13:35.930Z');
INSERT INTO misconfigurations VALUES('1a38b798-dc0d-4879-9187-46ba3daec2a1',2,'nginx','ssl_protocols','','ssl_protocols TLSv1.2 TLSv1.3;','N','N','M','P','N','N',0.0,0.0,'L','W','[]','','4.1.4','Without an explicit ssl_protocols directive, Nginx uses the OpenSSL default which historically includes TLSv1.0 and TLSv1.1. Explicit configuration is required to exclude deprecated protocol versions.','Add ''ssl_protocols TLSv1.2 TLSv1.3;'' to the http block.','absence','if_directive:ssl_certificate','','{"description": "The ssl_protocols directive specifies which SSL/TLS protocol versions are allowed for secure connections. Without an explicit configuration, Nginx may default to using deprecated protocols like TLSv1.0 and TLSv1.1, exposing the server to vulnerabilities such as POODLE or BEAST attacks.", "potential_impact": ["Expose the server to known vulnerabilities in older TLS versions", "Allow attackers to perform downgrade attacks", "Reduce security posture by enabling insecure ciphers"], "exploitation_scenario": {"prerequisites": ["An attacker must be able to intercept or manipulate network traffic between clients and the Nginx server.", "The attacker needs knowledge of vulnerabilities associated with older TLS versions."], "example": "An attacker could use a man-in-the-middle attack to force a client to downgrade its connection from a secure protocol like TLSv1.2 to an insecure one such as TLSv1.0, exploiting known weaknesses in the latter.", "result": "The attacker can intercept and decrypt sensitive data transmitted between clients and the server."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs to be positioned within the network to perform a man-in-the-middle attack or have knowledge of specific vulnerabilities in older TLS versions, which requires some level of expertise.", "c": "Why C=P: Confidentiality is partially compromised as an attacker can exploit weaknesses in deprecated TLS versions to intercept and decrypt sensitive data.", "i": "Why I=N: The misconfiguration does not directly allow for the modification of server-side files or configurations; however, it may indirectly lead to data leakage through vulnerabilities in older protocols.", "a": "Why A=N: Availability is not directly impacted by this misconfiguration as services remain accessible. However, a successful attack could disrupt service if clients refuse connections due to detected security issues.", "gel": "Why GEL=L: While exploitation of deprecated TLS versions can occur, it typically requires specific conditions and knowledge, making widespread attacks less frequent.", "grl": "Why GRL=W: There is extensive documentation available on how to properly configure Nginx for secure TLS usage."}}','2026-06-20T01:49:46.689Z','2026-06-20T04:16:14.845Z');
INSERT INTO misconfigurations VALUES('e5ab88ed-96c2-47b0-af8b-0e419f14833c',2,'nginx','ssl_stapling','','ssl_stapling on; ssl_stapling_verify on;','N','N','M','P','N','N',0.0,0.0,'L','W','[]','','4.1.7','Without OCSP stapling, clients must perform live OCSP lookups to the CA to verify certificate validity. This leaks browsing activity to the CA, degrades performance, and may allow revocation checks to be suppressed if the OCSP responder is unavailable.','Add ''ssl_stapling on; ssl_stapling_verify on; resolver 8.8.8.8;'' to the server block.','absence','if_directive:ssl_certificate','','{"description": "The directive ''ssl_stapling'' is used to enable OCSP (Online Certificate Status Protocol) stapling in Nginx. Without it enabled (''ssl_stapling on; ssl_stapling_verify on;''), clients must perform their own OCSP checks, which can leak browsing activity and degrade performance.", "potential_impact": ["Leak user''s browsing activity to the CA", "Decrease website performance due to additional network requests for OCSP", "Allow revocation checks to be suppressed if the OCSP responder is unavailable"], "exploitation_scenario": {"prerequisites": ["An attacker must observe or manipulate traffic between client and server", "Client''s browser must perform an OCSP check"], "example": "Attacker monitors network traffic for OCSP requests from a client to the CA. Client sends HTTP request to Nginx, which does not have ssl_stapling enabled, forcing the client to contact the CA directly.", "result": "The attacker gains visibility into the user''s browsing activity and can potentially manipulate or suppress revocation checks."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs to be in a position to observe network traffic between the client and server, which requires some level of network access or control.", "c": "Why C=P: The CA can see the user''s browsing activity when OCSP checks are performed by clients directly.", "i": "Why I=N: There is no direct impact on data modification as ssl_stapling does not affect server-side configurations or data integrity.", "a": "Why A=N: Availability is impacted due to potential performance degradation and network delays caused by client-initiated OCSP requests.", "gel": "Why GEL=L: While exploitation requires specific conditions, the misconfiguration can be commonly observed in less security-aware environments.", "grl": "Why GRL=W: Remediation steps are well-documented and straightforward to implement."}}','2026-06-20T01:49:46.691Z','2026-06-20T04:18:40.679Z');
INSERT INTO misconfigurations VALUES('931d9794-b653-4993-81c4-db38c237f5b8',3,'ssh','PermitRootLogin','yes','no','N','N','L','P','C','N',8.5,8.5,'H','H','[]','','5.1.20','PermitRootLogin set to ''yes'' allows direct root login via SSH, enabling any attacker who can guess or brute-force a password to gain full system access without further steps.','Set ''PermitRootLogin no'' in the /etc/ssh/sshd_config file and restart the sshd service.','value','always','','{"description": "The PermitRootLogin directive controls whether root login is allowed via SSH. Setting it to ''yes'' permits direct root access, which significantly increases the risk of unauthorized system compromise.", "potential_impact": ["Compromise full system control", "Execute arbitrary commands with root privileges", "Gain persistent access through compromised credentials"], "exploitation_scenario": {"prerequisites": ["Knowledge of a valid user account", "Ability to perform brute-force or dictionary attacks"], "example": "An attacker uses an SSH client to attempt login as root with guessed passwords: ssh root@target_ip -p 22", "result": "If the password is correct, the attacker gains full system access."}, "metric_justifications": {"ac": "Why AC=L: PermitRootLogin set to ''yes'' allows any attacker who can guess or brute-force a root password to gain immediate and unrestricted access without additional steps.", "c": "Why C=P: Sensitive information such as system configuration files, logs, and user data may be read by the attacker once they have gained root access.", "i": "Why I=C: The attacker can modify critical system configurations, install backdoors, or alter sensitive files to maintain persistent control over the compromised host.", "a": "Why A=N: Availability is not directly impacted as the service remains operational; however, denial-of-service attacks may be executed by the attacker once root access is obtained.", "gel": "Why GEL=H: PermitRootLogin set to ''yes'' is a common misconfiguration that frequently leads to successful exploitation due to its direct impact on system security.", "grl": "Why GRL=H: There are numerous resources and documentation available for remediation, making it easy to understand the risks and apply corrections."}}','2026-06-20T17:39:32.624Z','2026-06-20T17:52:35.572Z');
INSERT INTO misconfigurations VALUES('762bd697-4ca9-42f8-8d28-16284fd5081a',3,'ssh','PermitEmptyPasswords','yes','no','N','N','L','N','C','P',8.5,8.5,'H','H','["CVE-2016-6210", "CVE-2018-15473"]','','5.1.19','Allowing empty passwords enables attackers to easily brute-force accounts with weak or empty passwords, leading to full account compromise and potential system access.','Set ''PermitEmptyPasswords no'' in the /etc/ssh/sshd_config file.','value','always','','{"description": "The PermitEmptyPasswords directive allows users to log in with an empty password if set to ''yes'', which is highly insecure. This misconfiguration enables attackers to easily brute-force accounts and gain unauthorized access.", "potential_impact": ["Compromise user accounts", "Gain full system access", "Install backdoors or malware"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can attempt to log in with an empty password and gain unauthorized access if the account is not protected by other measures.", "result": "The attacker successfully logs into a user account, potentially escalating privileges and compromising system integrity."}, "metric_justifications": {"ac": "Why AC=L: Allowing empty passwords makes it trivial for an attacker to brute-force accounts with weak or no password protection. No special preconditions are required beyond sending login attempts.", "c": "Why C=N: The misconfiguration does not directly disclose sensitive information but allows unauthorized access, which can lead to further data exposure.", "i": "Why I=C: Once an attacker gains access through a compromised account, they may modify system configurations or install malicious software.", "a": "Why A=P: Availability is affected as the attacker can disrupt services by installing malware or altering critical system files.", "gel": "Why GEL=H: PermitEmptyPasswords misconfigurations are frequently exploited due to their simplicity and effectiveness in compromising systems.", "grl": "Why GRL=H: There is extensive documentation available on how to remediate this issue, making it easy for attackers to find instructions."}}','2026-06-20T17:40:23.534Z','2026-06-20T17:54:35.799Z');
INSERT INTO misconfigurations VALUES('96eb094d-eba2-48e3-9eb0-b347c3fa172e',3,'ssh','GSSAPIAuthentication','yes','no','N','N','L','P','N','N',5.0,5.0,'M','H','["CVE-2016-0738", "CVE-2019-6114"]','','5.1.9','Enabling GSSAPIAuthentication exposes the system to potential attacks leveraging GSSAPI, allowing an attacker to exploit vulnerabilities in this protocol. While it does not directly lead to full system compromise, it increases the attack surface and can be exploited if the attacker has knowledge of specific GSSAPI weaknesses.','Set ''GSSAPIAuthentication no'' in /etc/ssh/sshd_config.d/*.conf or /etc/ssh/sshd_config.','value','always','','{"description": "Enabling GSSAPIAuthentication allows for authentication using GSSAPI mechanisms. Setting this directive to ''yes'' exposes the system to potential attacks leveraging vulnerabilities in GSSAPI, such as CVE-2016-0738 and CVE-2019-6114.", "potential_impact": ["Exploits vulnerabilities in GSSAPI mechanisms", "Increases attack surface by enabling an additional authentication method", "Allows attackers to perform unauthorized actions if they can exploit specific weaknesses"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sends a malicious request exploiting a known vulnerability in GSSAPI, such as CVE-2016-0738 or CVE-2019-6114.", "result": "The attacker gains unauthorized access to the system through compromised authentication mechanisms."}, "metric_justifications": {"ac": "Why AC=L: Enabling GSSAPIAuthentication with ''yes'' makes it easy for an attacker to exploit known vulnerabilities in GSSAPI without any special preconditions.", "c": "Why C=P: The attacker can potentially disclose sensitive information or gain unauthorized access to system resources.", "i": "Why I=N: While the attack surface is increased, direct modification of data or configuration is not a guaranteed outcome and depends on further exploitation steps.", "a": "Why A=N: Availability is not directly impacted by enabling GSSAPIAuthentication; however, successful exploitation could lead to service disruption if critical resources are compromised.", "gel": "Why GEL=M: Exploitation of GSSAPI vulnerabilities has been observed in the wild and can be targeted with specific knowledge of system configurations.", "grl": "Why GRL=H: Detailed documentation on how to remediate GSSAPI vulnerabilities is widely available, making it easier for administrators to address these issues."}}','2026-06-20T17:41:26.540Z','2026-06-20T17:56:55.857Z');
INSERT INTO misconfigurations VALUES('6318fc26-6467-4b19-acb0-12dc8b3b7ee5',3,'ssh','HostbasedAuthentication','yes','no','N','N','M','P','C','N',7.79999999999999982,7.29999999999999982,'L','H','[]','','5.1.10','Enabling HostbasedAuthentication allows authentication via .rhosts and /etc/hosts.equiv files, which can be exploited by attackers with write access to these files. This requires local or network position to modify the files — AC is Medium.','Set ''HostbasedAuthentication no'' in the sshd configuration file.','value','always','','{"description": "HostbasedAuthentication allows authentication based on .rhosts and /etc/hosts.equiv files. Setting this to ''yes'' is dangerous because it permits unauthorized access if an attacker can modify these files.", "potential_impact": ["Compromise user accounts", "Gain unauthorized system access", "Deploy malicious code"], "exploitation_scenario": {"prerequisites": ["Write access to .rhosts or /etc/hosts.equiv files", "Network position to modify the files"], "example": "An attacker modifies a user''s .rhosts file in their home directory to include an entry for a compromised host, allowing them to authenticate without a password.", "result": "The attacker gains unauthorized access to the system as the targeted user."}, "metric_justifications": {"ac": "Why AC=M: Enabling HostbasedAuthentication requires an attacker to have write access to .rhosts or /etc/hosts.equiv files, which is a moderate barrier.", "c": "Why C=P: The attacker can read sensitive information and gain unauthorized access to user accounts.", "i": "Why I=C: The attacker can modify system configurations and deploy malicious code on the compromised host.", "a": "Why A=N: Availability is not directly affected, but the system becomes vulnerable to further attacks.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited compared to other vulnerabilities due to its specific requirements.", "grl": "Why GRL=H: There are numerous resources and documentation available for remediation."}}','2026-06-20T17:42:12.104Z','2026-06-20T17:58:54.229Z');
INSERT INTO misconfigurations VALUES('cd39e793-cef1-494e-af9b-f7fcd1647745',3,'ssh','IgnoreRhosts','no','yes','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','[]','','5.1.11','Setting IgnoreRhosts to ''no'' allows .rhosts and .shosts files to be used for authentication, which can lead to unauthorized access if these files exist on the system. Exploitation requires an attacker to have local or network access to place such files.','Set ''IgnoreRhosts yes'' in /etc/ssh/sshd_config.d/*.conf.','value','always','','{"description": "The IgnoreRhosts directive in OpenSSH Server is set to ''no'', which allows .rhosts and .shosts files to be used for authentication. This configuration can lead to unauthorized access if these files exist on the system, as they may contain insecurely configured host-based authentication.", "potential_impact": ["Allows an attacker to gain unauthorized access by placing malicious entries in .rhosts or .shosts files", "Enables a compromised user account to escalate privileges through improperly secured host-based authentication mechanisms", "Increases the attack surface for lateral movement within the network"], "exploitation_scenario": {"prerequisites": ["An attacker must have local or remote write access to place .rhosts or .shosts files on the target system", "The attacker needs knowledge of existing host-based authentication configurations"], "example": "An attacker places a malicious entry in the user''s home directory .rhosts file, such as ''user otherhost'', allowing them to authenticate without a password from that specific host.", "result": "The attacker gains unauthorized access to the system using the compromised host-based authentication mechanism."}, "metric_justifications": {"ac": "Why AC=M: Exploitation requires an attacker to have local or network write access, which presents a moderate barrier compared to trivially exploitable configurations.", "c": "Why C=P: The configuration allows for the disclosure of sensitive information through unauthorized access gained via compromised host-based authentication files.", "i": "Why I=P: An attacker can modify system configurations and data by leveraging improperly secured .rhosts or .shosts files to gain elevated privileges.", "a": "Why A=N: Availability is not directly impacted, but the system becomes vulnerable to further attacks due to unauthorized access.", "gel": "Why GEL=L: While exploitation requires specific conditions, it remains a common misconfiguration that can be easily overlooked in security audits.", "grl": "Why GRL=H: There are numerous resources and documentation available for remediation of this configuration issue."}}','2026-06-20T17:43:02.914Z','2026-06-20T18:01:23.021Z');
INSERT INTO misconfigurations VALUES('00a62236-5f74-402e-a340-016f5b9d4293',3,'ssh','PermitUserEnvironment','yes','no','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','[]','','5.1.21','Enabling PermitUserEnvironment allows users to set environment variables, potentially bypassing security controls and executing trojaned programs. However, exploitation requires the attacker to have SSH access, making AC Medium.','Set ''PermitUserEnvironment no'' in /etc/ssh/sshd_config or a configuration file included by it.','value','always','','{"description": "The PermitUserEnvironment directive allows users to set environment variables when they log in via SSH. Setting this value to ''yes'' is dangerous because it can enable attackers with SSH access to bypass security controls and execute malicious programs.", "potential_impact": ["Bypasses security controls", "Executes trojaned programs", "Modifies system configurations"], "exploitation_scenario": {"prerequisites": ["SSH access is required", "User has the ability to modify environment variables"], "example": "An attacker modifies their .ssh/environment or ~/.ssh/environment file to set malicious environment variables.", "result": "The system executes trojaned programs and potentially exposes sensitive information."}, "metric_justifications": {"ac": "Why AC=M: Exploitation requires SSH access, which is a moderate barrier as it necessitates authentication credentials or other means of gaining entry to the server.", "c": "Why C=P: Sensitive information can be disclosed through environment variables that are set by users with malicious intent.", "i": "Why I=P: The attacker can modify system configurations and execute arbitrary code via trojaned programs.", "a": "Why A=N: Availability is not directly impacted, but the integrity of the system may be compromised leading to indirect availability issues.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited as it requires specific conditions such as SSH access and user permissions.", "grl": "Why GRL=H: There are numerous resources available for remediation, including official documentation and security guidelines."}}','2026-06-20T17:43:47.500Z','2026-06-20T18:03:47.795Z');
INSERT INTO misconfigurations VALUES('f2be14ed-84a3-4093-ba31-7315be358ea2',3,'ssh','UsePAM','no','yes','N','N','M','N','N','P',4.29999999999999982,4.0,'L','H','[]','','5.1.22','Disabling UsePAM prevents PAM account and session processing, which can lead to degraded security features such as restricted access based on IP or time. However, this does not directly expose sensitive information or allow for immediate exploitation by remote attackers.','Set ''UsePAM yes'' in the sshd configuration file to enable proper PAM authentication and account/session processing.','value','always','','{"description": "The UsePAM directive enables PAM authentication and account/session processing for OpenSSH. Disabling it (setting to ''no'') can lead to a lack of security features such as IP or time-based access restrictions, which are crucial for securing SSH access.", "potential_impact": ["Decreases the ability to enforce strict access controls based on PAM policies", "Prevents use of advanced authentication methods and session management provided by PAM modules", "Reduces overall security posture due to missing critical security features"], "exploitation_scenario": {"prerequisites": ["An attacker must have knowledge of the disabled UsePAM configuration", "The attacker needs to exploit other vulnerabilities or gain initial access to the system"], "example": "A misconfigured SSH server with UsePAM set to ''no'' allows an attacker who has gained low-privilege access to bypass IP-based restrictions and time-of-day limitations that would normally be enforced by PAM.", "result": "The attacker can establish a persistent, unauthorized SSH session despite the presence of other security measures."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs additional knowledge about the system''s configuration and may require initial low-level access to exploit this misconfiguration effectively.", "c": "Why C=N: No sensitive information is directly exposed by disabling UsePAM, but security features are weakened.", "i": "Why I=N: The configuration itself cannot be modified without administrative privileges, but the system''s security posture can be exploited indirectly.", "a": "Why A=P: Availability may be affected if an attacker uses this misconfiguration to establish a persistent unauthorized session or escalate privileges.", "gel": "Why GEL=L: While not trivially exploitable by any attacker, the impact is significant for systems where PAM-based security measures are critical.", "grl": "Why GRL=H: There is extensive documentation and guidance available on how to properly configure UsePAM in OpenSSH."}}','2026-06-20T17:44:37.622Z','2026-06-20T18:06:50.378Z');
INSERT INTO misconfigurations VALUES('b8bb484b-e312-48a5-8283-0cba4e46f323',3,'ssh','LogLevel','QUIET','VERBOSE','N','N','L','N','N','P',5.0,5.0,'M','H','[]','','5.1.14','Setting LogLevel to QUIET disables most logging, making it difficult to detect and respond to security incidents. This can lead to gradual degradation of system monitoring capabilities.','Set ''LogLevel VERBOSE'' or ''LogLevel INFO'' in the sshd_config file.','value','always','','{"description": "The LogLevel directive in OpenSSH Server controls the verbosity of logging. Setting LogLevel to QUIET disables most logging, which can severely hinder incident detection and response efforts.", "potential_impact": ["Disable critical security event logging", "Compromise forensic capabilities during an attack", "Reduce visibility into unauthorized access attempts"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can exploit this misconfiguration by simply connecting to the SSH server and performing malicious actions without being logged. The lack of logging makes it difficult to trace back any suspicious activities.", "result": "The attacker''s actions go undetected due to the absence of logs, allowing them to potentially escalate privileges or exfiltrate data."}, "metric_justifications": {"ac": "Why AC=L: Setting LogLevel to QUIET is trivially exploitable by any user who connects to the SSH server. No special conditions are required beyond initiating a connection.", "c": "Why C=N: There is no direct confidentiality impact as sensitive information is not disclosed through logging.", "i": "Why I=N: The misconfiguration does not allow for immediate modification of system data or configuration files.", "a": "Why A=P: Availability can be indirectly affected due to the inability to detect and respond to security incidents in a timely manner.", "gel": "Why GEL=M: Misconfigurations like this are moderately common as administrators may overlook the importance of logging verbosity.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure LogLevel for OpenSSH Server."}}','2026-06-20T17:45:16.577Z','2026-06-20T18:09:06.033Z');
INSERT INTO misconfigurations VALUES('94495d9b-f3ff-4d0c-9e04-b3d449b2cc0f',3,'ssh','MaxAuthTries','6','4','N','N','L','N','N','P',5.0,5.0,'M','H','[]','','5.1.16','Increasing MaxAuthTries to 6 allows more login attempts, increasing the risk of successful brute force attacks. This can lead to gradual degradation of system security through unauthorized access.','Set ''MaxAuthTries 4'' in /etc/ssh/sshd_config.d/*.conf or directly in /etc/ssh/sshd_config.','value','always','','{"description": "The MaxAuthTries directive limits the number of authentication attempts before disconnecting the client. Setting it to 6 increases the risk of successful brute force attacks by allowing more login attempts.", "potential_impact": ["Increases likelihood of unauthorized access through brute force", "Exposes system to prolonged attack vectors", "Reduces security posture over time due to repeated failed attempts"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker uses a tool like Hydra or Medusa to repeatedly attempt login with different credentials. The SSH server allows up to 6 incorrect password attempts before disconnecting.", "result": "The attacker gains unauthorized access if they discover the correct credentials within the allowed number of attempts."}, "metric_justifications": {"ac": "Why AC=L: An unauthenticated attacker can easily perform brute force attacks by sending multiple login requests, each attempt being simple and requiring no special permissions.", "c": "Why C=N: No sensitive information is disclosed beyond the fact that authentication attempts are allowed up to 6 times.", "i": "Why I=N: The configuration does not allow for modification of system data or settings through brute force attacks alone.", "a": "Why A=P: Availability can be impacted as repeated login attempts may cause denial-of-service conditions by consuming server resources.", "gel": "Why GEL=M: This type of misconfiguration is frequently exploited due to the ease and effectiveness of automated brute force tools.", "grl": "Why GRL=H: There are numerous guides and documentation available on how to properly secure SSH servers, including setting appropriate MaxAuthTries values."}}','2026-06-20T17:46:04.399Z','2026-06-20T18:11:18.781Z');
INSERT INTO misconfigurations VALUES('836f8499-68b4-41d4-a270-e28ccf2e614d',3,'ssh','MaxSessions','20','10','N','N','L','N','N','P',5.0,5.0,'M','H','[]','','5.1.18','Setting MaxSessions to a high value like ''20'' can lead to resource exhaustion and degrade the availability of SSH services, making it easier for attackers to perform DoS attacks.','Set ''MaxSessions 10'' or lower in /etc/ssh/sshd_config.d/*.conf file.','value','always','','{"description": "The MaxSessions directive limits the maximum number of concurrent sessions per connection. Setting it to ''20'' can lead to resource exhaustion and degrade SSH service availability, making DoS attacks more feasible.", "potential_impact": ["Degradation of SSH service availability", "Resource exhaustion on the server", "Increased susceptibility to DoS attacks"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can initiate multiple simultaneous connections, each with a high number of sessions (up to 20), overwhelming the SSH service and causing resource depletion.", "result": "The SSH server becomes unresponsive or unavailable for legitimate users."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily initiate multiple simultaneous connections with a high number of sessions, exploiting the MaxSessions setting without needing special privileges or conditions beyond sending requests.", "c": "Why C=N: No sensitive information is disclosed directly by this misconfiguration.", "i": "Why I=N: The configuration itself cannot be modified through this vulnerability alone.", "a": "Why A=P: Availability of the SSH service can be significantly impacted due to resource exhaustion and DoS attacks.", "gel": "Why GEL=M: This type of misconfiguration is moderately likely to be exploited in environments where attackers seek to disrupt services.", "grl": "Why GRL=H: There are numerous resources available for remediation, including official documentation and security guidelines."}}','2026-06-20T17:46:48.854Z','2026-06-20T18:13:35.745Z');
INSERT INTO misconfigurations VALUES('a8660d73-2e3e-46cf-ab1c-49e42dbd51d1',3,'ssh','LoginGraceTime','120','60','N','N','L','N','N','P',5.0,5.0,'M','H','[]','','5.1.13','A longer LoginGraceTime increases the window for brute force attacks and unauthorized access attempts, potentially leading to service degradation due to excessive unauthenticated connections.','Set ''LoginGraceTime 60'' in /etc/ssh/sshd_config.d/*.conf or directly in /etc/ssh/sshd_config.','value','always','','{"description": "The LoginGraceTime directive sets the time limit for users to authenticate after attempting to log in via SSH. A value of 120 seconds increases the window during which brute force attacks can occur, making it easier for attackers to attempt multiple login combinations without being disconnected.", "potential_impact": ["Increases the likelihood of successful brute-force attacks due to extended authentication time", "Leads to service degradation as more unauthenticated connections are maintained longer", "Potentially exposes sensitive information during prolonged connection attempts"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker uses an automated tool like Hydra or Medusa to perform SSH login brute force attacks, taking advantage of the extended grace period to attempt numerous password guesses.", "result": "The attacker successfully gains unauthorized access after multiple attempts within the 120-second window."}, "metric_justifications": {"ac": "Why AC=L: The ease with which an attacker can exploit a longer LoginGraceTime is low, as it only requires sending repeated login requests without any additional technical barriers.", "c": "Why C=N: No sensitive information is disclosed beyond what would normally be exposed during a failed SSH authentication attempt.", "i": "Why I=N: The configuration itself cannot be modified directly through this attack vector; however, the system''s availability can be impacted.", "a": "Why A=P: Availability is affected as the server may become unresponsive due to excessive connection attempts and prolonged grace periods for failed logins.", "gel": "Why GEL=M: This type of misconfiguration is frequently exploited by attackers looking to gain unauthorized access through brute force methods.", "grl": "Why GRL=H: Remediation documentation is widely available, making it straightforward to correct the LoginGraceTime setting."}}','2026-06-20T17:47:39.311Z','2026-06-20T18:17:15.273Z');
INSERT INTO misconfigurations VALUES('bcb40611-ca1e-4d0e-90a4-ed88b0372118',3,'ssh','Ciphers','3des-cbc','aes256-ctr,aes192-ctr,aes128-ctr','N','N','L','P','N','N',5.0,5.0,'M','H','["CVE-2023-48795"]','','5.1.6','Using the weak cipher ''3des-cbc'' can allow attackers to exploit known vulnerabilities in this encryption algorithm, leading to potential data compromise and unauthorized access.','Remove ''3des-cbc'' from the list of ciphers and ensure that only strong ciphers such as chacha20-poly1305@openssh.com are used.','value','always','','{"description": "The Ciphers directive specifies the encryption algorithms used for SSH connections. Using ''3des-cbc'' is dangerous because it is known to be vulnerable to various cryptographic attacks that can lead to data compromise.", "potential_impact": ["Compromise sensitive information transmitted over the network", "Allow attackers to decrypt intercepted traffic", "Enable unauthorized access to systems"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker can exploit a known vulnerability in 3des-cbc by intercepting and analyzing encrypted SSH traffic.", "result": "The attacker gains the ability to decrypt sensitive data transmitted over the compromised connection."}, "metric_justifications": {"ac": "Why AC=L: An attacker with access to network traffic can easily exploit vulnerabilities in ''3des-cbc'' without any special preconditions, making it trivial.", "c": "Why C=P: The confidentiality of data transmitted over the SSH connection is compromised as attackers can decrypt intercepted communications.", "i": "Why I=N: There are no known mechanisms for an attacker to modify or inject data into the encrypted stream using ''3des-cbc'' alone.", "a": "Why A=N: Availability is not directly impacted by the use of ''3des-cbc''; however, successful exploitation can lead to denial-of-service if legitimate users cannot authenticate due to compromised credentials.", "gel": "Why GEL=M: Misconfigurations involving weak ciphers like ''3des-cbc'' are frequently exploited in real-world scenarios due to their known vulnerabilities.", "grl": "Why GRL=H: There is extensive documentation and guidance available on how to remediate the use of weak ciphers, making it straightforward for security professionals to address this issue."}}','2026-06-20T17:48:35.396Z','2026-06-20T18:20:46.064Z');
INSERT INTO misconfigurations VALUES('191a249a-da35-41c6-8459-22177f6f93a1',3,'ssh','MACs','hmac-md5','hmac-sha2-256,hmac-sha2-512','N','N','M','P','P','N',5.79999999999999982,5.79999999999999982,'H','H','["CVE-2023-48795"]','','5.1.15','Using weak MAC algorithms like hmac-md5 increases the risk of SSH downgrade attacks, allowing an attacker with a MITM position to decrypt the SSH tunnel and capture credentials. This requires specific network conditions but is actively exploited.','Remove ''hmac-md5'' from the list of allowed MACs in /etc/ssh/sshd_config.d/*.conf and ensure only strong algorithms are used.','value','always','','{"description": "The MACs directive specifies message authentication codes used to ensure data integrity and authenticity in SSH sessions. Using hmac-md5 is dangerous because it is a weak algorithm that can be exploited by attackers to perform downgrade attacks, compromising the security of SSH communications.", "potential_impact": ["Decrypt SSH tunnel traffic", "Capture credentials during login attempts", "Perform man-in-the-middle (MITM) attacks"], "exploitation_scenario": {"prerequisites": ["Attacker must be in a position to intercept network traffic between the client and server", "Client and server must negotiate hmac-md5 as an acceptable MAC algorithm"], "example": "An attacker can use tools like Wireshark or custom scripts to monitor SSH sessions and exploit weak MAC algorithms. For instance, by capturing and analyzing packets during a session setup, they could identify the use of hmac-md5 and attempt to downgrade the connection.", "result": "The attacker successfully decrypts the SSH tunnel traffic, allowing them to capture sensitive information such as login credentials."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs a specific network position to intercept and manipulate SSH sessions. This moderate barrier makes it less trivial than low but not as complex as high.", "c": "Why C=P: The confidentiality of sensitive data, such as login credentials, is compromised due to the ability to decrypt intercepted traffic.", "i": "Why I=P: While integrity may be affected by the attacker''s ability to manipulate sessions, there are no direct modifications to system configurations or data.", "a": "Why A=N: Availability is not directly impacted; however, successful exploitation can lead to denial of service if legitimate users cannot authenticate due to compromised credentials.", "gel": "Why GEL=H: Weak MAC algorithms like hmac-md5 are frequently targeted and exploited in real-world scenarios, making this a high-exploitation likelihood issue.", "grl": "Why GRL=H: There is extensive documentation available on how to remediate weak MAC configurations, including detailed guides and best practices."}}','2026-06-20T17:49:32.551Z','2026-06-20T18:24:30.079Z');
INSERT INTO misconfigurations VALUES('6923d461-0ad0-4df2-aec0-efda9f35784f',3,'ssh','ClientAliveInterval','','ClientAliveInterval 15','N','N','L','P','N','N',0.0,0.0,'L','W','[]','','5.1.7','Without ClientAliveInterval, sshd never probes idle clients, so a session whose network connection has dropped can remain open and consume resources or be hijacked from an unattended terminal.','Set ''ClientAliveInterval 15'' (with ClientAliveCountMax 3).','absence','always','','{"description": "The ClientAliveInterval directive in OpenSSH Server specifies how often the server sends a null packet to clients to check if they are still connected. Without setting this value (i.e., leaving it as default or unset), an idle SSH session can remain open indefinitely, potentially leading to resource consumption and security risks.", "potential_impact": ["Consumes unnecessary system resources by maintaining idle connections", "Allows unauthorized access from hijacked terminals if the user leaves their terminal unattended", "Increases risk of data leakage or command injection through compromised sessions"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can exploit an open, idle SSH session by gaining physical access to a terminal where an authenticated user has left the system unattended. The attacker then uses this opportunity to hijack the session.", "result": "The attacker gains unauthorized access to the system through the compromised SSH session."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit an idle SSH session by simply gaining physical or network access to a terminal where an unattended, authenticated user''s session is open. No special preconditions are required.", "c": "Why C=P: The attacker can potentially read sensitive data or execute commands on the system through the hijacked SSH session.", "i": "Why I=N: There is no direct modification of data or configuration possible through this misconfiguration alone, but indirect modifications could occur via command execution in the hijacked session.", "a": "Why A=N: The availability impact is primarily due to resource consumption from idle sessions and potential disruption caused by unauthorized access.", "gel": "Why GEL=L: This type of misconfiguration is common and frequently exploited when not properly managed, especially in environments with lax security practices or unattended terminals.", "grl": "Why GRL=W: There are numerous resources available for remediation, including official documentation and best practice guides from the OpenSSH project."}}','2026-06-20T17:49:32.554Z','2026-06-20T18:27:53.653Z');
INSERT INTO misconfigurations VALUES('64a96c46-4e6b-4215-a413-55221af75b2d',3,'ssh','ClientAliveCountMax','','ClientAliveCountMax 3','N','N','L','P','N','N',0.0,0.0,'L','W','[]','','5.1.7','Without ClientAliveCountMax, sshd does not bound how many missed keepalive probes are tolerated, so unresponsive sessions are not terminated, leaving idle authenticated channels open.','Set ''ClientAliveCountMax 3'' (with ClientAliveInterval 15).','absence','always','','{"description": "The ClientAliveCountMax directive sets the maximum number of client keepalive probe failures before an idle SSH session is terminated. Without this setting (i.e., when it''s not configured), unresponsive sessions remain open indefinitely, allowing authenticated users to maintain persistent access even if their connection drops or becomes inactive.", "potential_impact": ["Allows unauthorized persistence in the network by maintaining idle SSH connections", "Enables attackers to exploit idle sessions for lateral movement and reconnaissance", "Increases risk of resource exhaustion on the server due to excessive open connections"], "exploitation_scenario": {"prerequisites": ["Establish an authenticated SSH session", "Ensure no ClientAliveCountMax is set"], "example": "ssh user@host -N -T & (to establish a background idle connection)", "result": "An attacker can maintain an open, unmonitored SSH session indefinitely, allowing them to re-establish access without needing credentials again."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily exploit this misconfiguration by simply establishing and maintaining an idle SSH connection. No special preconditions are required beyond having authenticated access.", "c": "Why C=P: The impact is primarily on the server''s resource utilization, but no specific information disclosure occurs directly from this misconfiguration alone.", "i": "Why I=N: There is no direct modification of data or configuration possible through this vulnerability; it merely extends session persistence.", "a": "Why A=N: Availability can be indirectly affected due to potential resource exhaustion from excessive idle connections, but the server remains operational.", "gel": "Why GEL=L: This type of misconfiguration is common and easily exploitable by attackers once they have initial access, making it a frequent target in opportunistic attacks.", "grl": "Why GRL=W: Remediation documentation for setting ClientAliveCountMax is widely available and straightforward to implement."}}','2026-06-20T17:49:32.556Z','2026-06-20T18:32:34.161Z');
INSERT INTO misconfigurations VALUES('d6a6f9c8-4fb7-4d40-9879-112fc53cdff6',3,'ssh','Banner','','Banner /etc/issue.net','N','N','L','P','N','N',0.0,0.0,'L','W','[]','','5.1.5','Without a Banner, sshd presents no legal/authorised-use warning before authentication, weakening the deterrent and legal posture against unauthorised access.','Set ''Banner /etc/issue.net'' and populate the banner file.','absence','always','','{"description": "The Banner directive in OpenSSH Server is used to display a message before authentication occurs. Without setting this directive to ''Banner /etc/issue.net'', there is no legal or authorized-use warning presented to users, which can weaken deterrence against unauthorized access.", "potential_impact": ["Exposes the system to potential legal and reputational risks due to lack of clear usage policies", "Reduces the effectiveness of legal warnings in discouraging malicious activities", "Decreases user awareness about proper use and security measures"], "exploitation_scenario": {"prerequisites": [], "example": "A user connects to the SSH server using a standard SSH client. Upon connection, no banner message is displayed.", "result": "The user does not see any legal or authorized-use warning before attempting authentication."}, "metric_justifications": {"ac": "AC=L: Displaying a banner upon SSH login requires no special conditions beyond connecting to the server; it is trivially easy for an attacker to observe.", "c": "C=P: No sensitive information is disclosed, but the lack of a warning message can lead to misuse or unauthorized access.", "i": "I=N: There is no direct impact on system configuration or data modification through this misconfiguration alone.", "a": "A=N: Availability is not directly impacted by the absence of a banner; however, it indirectly affects security posture and user behavior.", "gel": "GEL=L: This type of misconfiguration is common and frequently exploited due to its simplicity in detection and lack of deterrent effect.", "grl": "GRL=W: Remediation steps are well-documented and straightforward, requiring only the addition of a banner file and configuration directive."}}','2026-06-20T17:49:32.559Z','2026-06-20T18:35:27.315Z');
INSERT INTO misconfigurations VALUES('8190b181-6674-4881-a6c6-838ace975ed9',3,'ssh','DisableForwarding','','DisableForwarding yes','N','N','L','P','N','N',0.0,0.0,'L','W','[]','','5.1.8','Without DisableForwarding, sshd permits TCP/X11/agent forwarding by default, which can be abused to pivot through the host or tunnel traffic past network controls.','Set ''DisableForwarding yes'' unless forwarding is required.','absence','always','','{"description": "The DisableForwarding directive in OpenSSH Server prevents users from forwarding TCP connections, X11 sessions, and SSH agent connections. Without ''DisableForwarding yes'', an attacker can exploit these features to pivot through the host or tunnel traffic past network controls.", "potential_impact": ["Abuse TCP forwarding to exfiltrate data", "Establish a reverse shell for persistent access", "Bypass network security measures by tunneling traffic"], "exploitation_scenario": {"prerequisites": ["An attacker with SSH login credentials"], "example": "A user logs in and runs ''ssh -R 0:localhost:22 user@target'' to set up a reverse SSH tunnel.", "result": "The attacker can now use the compromised host as an intermediary to access other internal systems or bypass network restrictions."}, "metric_justifications": {"ac": "Why AC=L: An attacker with valid credentials can easily exploit TCP forwarding without any additional steps, making it trivially exploitable.", "c": "Why C=P: The attacker can potentially exfiltrate sensitive data through the forwarded connections.", "i": "Why I=N: While the configuration itself cannot be modified directly via this vulnerability, the impact is on network and system access rather than direct modification of files or settings.", "a": "Why A=N: Availability is not directly impacted as the service continues to function normally; however, availability of other systems through pivoting can be compromised.", "gel": "Why GEL=L: This type of misconfiguration is frequently exploited in real-world scenarios due to its simplicity and effectiveness.", "grl": "Why GRL=W: There are numerous resources available for remediation including official documentation and security guidelines."}}','2026-06-20T17:49:32.561Z','2026-06-20T18:38:20.149Z');
INSERT INTO misconfigurations VALUES('c647122b-2e35-460f-a419-8b238dac5d9b',4,'mysql','ssl_cipher','*','ECDHE-ECDSA-AES128-GCM-SHA256','N','N','L','P','N','N',5.0,4.70000000000000017,'L','H','[]','','2.10','Module enabled unnecessarily.','Disable this module.','value','always','','{"description": "The ssl_cipher directive specifies which SSL/TLS ciphers are allowed for encrypted connections. Setting it to ''*'' allows all available ciphers, including weak and deprecated ones, making the connection vulnerable to various attacks.", "potential_impact": ["Expose the server to downgrade attacks where weaker ciphers can be forced", "Enable interception of data by attackers using known vulnerabilities in older ciphers", "Reduce overall security posture due to lack of cipher suite control"], "exploitation_scenario": {"prerequisites": ["An attacker with network access to intercept traffic"], "example": "Attacker sends a request to the server specifying an insecure cipher like RC4-SHA and forces the connection to use it.", "result": "The encrypted communication is vulnerable, allowing interception and decryption of sensitive data."}, "metric_justifications": {"ac": "AC=L: An attacker can easily exploit this misconfiguration by simply forcing a weak cipher during the SSL/TLS handshake without needing any special privileges or additional preconditions.", "c": "C=P: The exposure allows attackers to read and potentially decrypt sensitive data transmitted over the connection.", "i": "I=N: While the server''s configuration can be modified, there is no direct impact on modifying data through this misconfiguration alone.", "a": "A=N: Availability of services is not directly impacted by this misconfiguration; however, it may indirectly affect service integrity if sensitive data is compromised.", "gel": "GEL=L: This type of misconfiguration is frequently exploited due to the ease with which attackers can force weak ciphers and intercept communications.", "grl": "GRL=H: There are extensive resources available for remediation, including detailed documentation on configuring secure cipher suites."}}','2026-06-21T23:27:20.271Z','2026-06-22T00:38:30.641Z');
INSERT INTO misconfigurations VALUES('0af46c3f-f419-4aa9-aa8d-176eb4cd28be',4,'mysql','plugin-load','','validate_password.so','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','','2.6','Not loading the validate_password plugin allows users to set weak passwords, potentially leading to database compromise through brute-force or guessing attacks. However, exploitation requires an attacker to have access to the system where they can modify password policies.','Ensure ''plugin-load=validate_password.so'' is present in my.cnf and configure global validate_password settings as per organizational policy.','value','always','','{"description": "The ''plugin-load'' directive specifies which plugins are loaded at MySQL startup. Not loading the validate_password plugin allows users to set weak passwords, potentially leading to database compromise through brute-force or guessing attacks.", "potential_impact": ["Allows attackers to exploit weak password policies", "Increases risk of unauthorized access via compromised credentials", "Reduces overall security posture by enabling insecure practices"], "exploitation_scenario": {"prerequisites": ["An attacker must have write access to the MySQL configuration files or the ability to modify server settings", "The attacker needs knowledge of how to exploit weak password policies"], "example": "A malicious user modifies the my.cnf file to include ''validate_password=off'' and restarts the MySQL service, disabling the validate_password plugin.", "result": "The attacker can now create a new database account with a very weak password, such as ''password123'', making it easy for them to gain unauthorized access."}, "metric_justifications": {"ac": "Why AC=M: Exploitation requires write access to the MySQL configuration files or server settings, which is not trivial but still feasible with sufficient privileges.", "c": "Why C=P: No sensitive information is directly disclosed; however, the attacker can exploit weak credentials to gain unauthorized access.", "i": "Why I=N: The misconfiguration does not allow for direct data modification without first compromising a user account using weak passwords.", "a": "Why A=N: Availability is not directly impacted by this misconfiguration, but compromised accounts could be used in denial-of-service attacks or other disruptive activities.", "gel": "Why GEL=L: While the impact can be severe, exploitation typically requires specific conditions to be met and is less frequent than low-hanging fruit vulnerabilities.", "grl": "Why GRL=H: There are numerous resources available for understanding and mitigating this type of misconfiguration, including official MySQL documentation."}}','2026-06-21T23:30:34.241Z','2026-06-22T00:43:20.986Z');
INSERT INTO misconfigurations VALUES('d4d82ca8-dbc8-4d17-a3c7-78f9c8ea6a8d',4,'mysql','block_encryption_mode','aes-128-ecb','aes-256-cbc','N','N','M','P','P','N',5.79999999999999982,5.79999999999999982,'H','H','["CVE-2016-8619", "CVE-2017-1309"]','','2.7','Using ''aes-128-ecb'' for encryption is highly insecure due to its susceptibility to known plaintext attacks and lack of diffusion. While an attacker needs specific preconditions (such as access to encrypted data), the misconfiguration significantly increases the risk of data compromise.','Set ''block_encryption_mode=aes-256-cbc'' in /etc/my.cnf for enhanced security.','value','always','','{"description": "The ''block_encryption_mode'' directive in MySQL determines the encryption mode used for data at rest. Using ''aes-128-ecb'' is highly insecure due to its susceptibility to known plaintext attacks and lack of diffusion, making it easier for attackers to decrypt sensitive information.", "potential_impact": ["Disclose sensitive data stored in encrypted tables", "Enable unauthorized access to database contents", "Compromise the confidentiality of user credentials"], "exploitation_scenario": {"prerequisites": ["Access to encrypted MySQL data files or backups", "Knowledge of the encryption key used by MySQL"], "example": "An attacker with access to a MySQL backup file can use known plaintext attacks to decrypt sensitive information stored in tables using aes-128-ecb.", "result": "The attacker gains unauthorized access to encrypted data, compromising confidentiality and integrity."}, "metric_justifications": {"ac": "Medium: An attacker needs specific preconditions such as access to encrypted MySQL data files or backups, making it moderately difficult but not impossible for an attacker to exploit this misconfiguration.", "c": "Partial: The configuration allows attackers to read and decrypt sensitive information stored in the database.", "i": "Partial: While the encryption mode does not directly allow modification of data, the exposure of decrypted data can lead to further attacks that modify or corrupt the database.", "a": "None: There is no direct impact on availability; however, compromised confidentiality may indirectly affect system integrity and availability through secondary attacks.", "gel": "High: Known plaintext attacks against aes-128-ecb are well-documented and frequently exploited in real-world scenarios.", "grl": "High: Extensive documentation exists for understanding the risks associated with using weak encryption modes like aes-128-ecb."}}','2026-06-21T23:34:01.743Z','2026-06-22T00:48:12.037Z');
INSERT INTO misconfigurations VALUES('de446755-ee1a-4d2d-a82f-7912ab005f5b',4,'mysql','bind_address','*','192.0.2.24','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','2.9','Setting bind_address to ''*'' allows MySQL to accept connections from any IP address, potentially exposing the database to unauthorized access and attacks from remote unauthenticated attackers.','Set ''bind_address'' to a specific IPv4 or IPv6 address in the [mysqld] section of /etc/my.cnf.','value','always','','{"description": "The bind_address directive specifies which IP address MySQL listens on for incoming connections. Setting it to ''*'' allows MySQL to accept connections from any IP address, potentially exposing the database to unauthorized access and attacks from remote unauthenticated attackers.", "potential_impact": ["Expose the database to unauthorized access", "Allow remote attackers to exploit vulnerabilities in MySQL", "Enable data exfiltration or modification by malicious actors"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker can connect to the MySQL server using a standard SQL client and attempt to log in with default credentials or through brute force attacks.", "result": "The attacker gains unauthorized access to the database, potentially allowing them to read sensitive data, modify records, or execute arbitrary commands."}, "metric_justifications": {"ac": "Why AC=L: Setting bind_address to ''*'' makes it trivial for any unauthenticated attacker to connect and attempt exploitation with a standard SQL client.", "c": "Why C=P: The exposure allows attackers to read sensitive data stored in the database, such as user credentials or financial information.", "i": "Why I=N: While the configuration does not inherently allow modification of all data, it enables unauthorized access which can be leveraged for further attacks that modify data.", "a": "Why A=N: The availability of the service is not directly impacted by this misconfiguration; however, successful exploitation could lead to denial-of-service conditions if the attacker disrupts database operations.", "gel": "Why GEL=M: Misconfigurations like exposing MySQL to all IP addresses are common and frequently exploited in automated attacks.", "grl": "Why GRL=H: There is extensive documentation available on how to properly secure MySQL, including setting bind_address to a specific IP address."}}','2026-06-21T23:35:55.370Z','2026-06-22T00:52:33.905Z');
INSERT INTO misconfigurations VALUES('08d625b2-3475-4efc-a129-625f7cfc3d22',4,'mysql','allow-suspicious-udfs','ON','OFF','N','N','M','P','C','N',7.79999999999999982,7.29999999999999982,'L','H','[]','','4.3','Allowing suspicious user-defined functions can enable attackers with write access to the web root or specific network positions to load arbitrary shared libraries, potentially leading to remote code execution. However, this requires additional preconditions such as local file write access.','Set ''allow-suspicious-udfs'' to ''OFF''.','value','always','','{"description": "The directive ''allow-suspicious-udfs'' enables MySQL to load and execute user-defined functions from shared libraries. Setting this value to ON is dangerous because it allows attackers with write access to the web root or specific network positions to inject malicious code, potentially leading to remote code execution.", "potential_impact": ["Discloses system information", "Enables unauthorized modification of database configurations and data", "Potentially leads to full server compromise"], "exploitation_scenario": {"prerequisites": ["Write access to the MySQL configuration or web root directory", "Ability to place a malicious shared library in the specified path"], "example": "An attacker with write access places a malicious .so file in /var/lib/mysqludf/. The attacker then uses SQL commands like CREATE FUNCTION to load this UDF into MySQL.", "result": "The attacker can execute arbitrary code on the server, leading to full control over the database and potentially the entire system."}, "metric_justifications": {"ac": "Why AC=M: Allowing suspicious user-defined functions requires an attacker to have write access to specific directories or network positions, which is a moderate barrier but not trivial.", "c": "Why C=P: The configuration and system information can be disclosed through the execution of malicious UDFs.", "i": "Why I=C: Database configurations and data can be modified by executing arbitrary code via suspicious user-defined functions.", "a": "Why A=N: Availability is not directly affected, but the server may become unstable or crash due to malicious activities.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited in practice compared to more common vulnerabilities.", "grl": "Why GRL=H: There are extensive remediation guides and documentation available for securing MySQL against suspicious UDFs."}}','2026-06-21T23:37:38.995Z','2026-06-22T00:57:00.338Z');
INSERT INTO misconfigurations VALUES('07ada9e8-a0a8-4b66-9568-c7ca1118afcb',4,'mysql','local_infile','ON','OFF','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','["CVE-2016-6662", "CVE-2017-3594"]','','4.4','Enabling local_infile allows an attacker to read files from the MySQL client''s filesystem via SQL injection, but this requires a specific vulnerability and access to execute SQL commands.','Set ''local_infile=OFF'' in the [mysqld] section of the MySQL configuration file and restart the service.','value','always','','{"description": "The local_infile directive allows MySQL clients to load data from local files when executing SQL commands. Setting it to ON is dangerous because an attacker can exploit this feature via SQL injection to read sensitive files on the server.", "potential_impact": ["Read arbitrary files on the filesystem", "Steal credentials and configuration details", "Gain insights into system architecture"], "exploitation_scenario": {"prerequisites": ["An attacker must have write access to execute SQL commands", "The target MySQL server has local_infile enabled"], "example": "A malicious user injects an SQL command like ''SELECT LOAD_FILE(''/etc/passwd'') INTO OUTFILE ''/tmp/output.txt'';'' into a vulnerable application.", "result": "The attacker successfully reads the contents of /etc/passwd and writes it to /tmp/output.txt."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs write access to execute SQL commands, which is not trivial but still feasible in many environments.", "c": "Why C=P: The attacker can read sensitive files such as configuration and credential files.", "i": "Why I=P: The attacker may modify data or configurations by writing malicious content back to the filesystem via SQL commands.", "a": "Why A=N: Availability is not directly impacted, but persistent access could lead to further exploitation affecting availability.", "gel": "Why GEL=L: This type of misconfiguration is exploited less frequently as it requires specific conditions and vulnerabilities.", "grl": "Why GRL=H: There are extensive resources available for understanding and mitigating the risks associated with local_infile."}}','2026-06-21T23:39:30.645Z','2026-06-22T01:01:04.405Z');
INSERT INTO misconfigurations VALUES('17851e85-f7cf-4e7e-a269-a5f4ab8e4b92',4,'mysql','skip-grant-tables','TRUE','FALSE','N','N','L','C','C','N',9.40000000000000035,9.40000000000000035,'H','H','[]','','4.5','Enabling ''--skip-grant-tables'' allows all clients unrestricted access to the MySQL server, leading to full data disclosure and arbitrary database modifications without authentication.','Set ''skip-grant-tables = FALSE'' in the MySQL configuration file (e.g., my.cnf).','value','always','','{"description": "The ''--skip-grant-tables'' directive in MySQL allows all clients unrestricted access to the server when set to TRUE. This is extremely dangerous as it bypasses all authentication mechanisms, enabling any user to perform administrative actions without credentials.", "potential_impact": ["Discloses full database content", "Enables arbitrary data modifications", "Allows creation of new users and privileges"], "exploitation_scenario": {"prerequisites": ["None"], "example": "A malicious user connects to the MySQL server using a simple SQL client command: mysql -h hostname -u anyuser. Since skip-grant-tables is enabled, no password or authentication is required.", "result": "The attacker gains full administrative access and can read/write/delete all data in the database."}, "metric_justifications": {"ac": "Why AC=L: Enabling ''--skip-grant-tables'' makes it trivial for any user to connect without authentication, requiring no special skills or preconditions.", "c": "Why C=C: All sensitive information stored in the MySQL database is readable by anyone who can connect to the server.", "i": "Why I=C: The attacker can modify all data and create new users with administrative privileges, leading to full control over the system.", "a": "Why A=N: Availability is not directly impacted as the service remains operational; however, it becomes a critical security risk due to unauthorized access.", "gel": "Why GEL=H: Misconfigurations like ''--skip-grant-tables'' are common and frequently exploited by attackers seeking easy access to databases.", "grl": "Why GRL=H: There is extensive documentation available on how to properly secure MySQL, making it clear that this setting should be disabled."}}','2026-06-21T23:41:24.116Z','2026-06-22T01:05:14.658Z');
INSERT INTO misconfigurations VALUES('7eaf780e-c497-422a-a4dd-b0d979f98fd5',4,'mysql','skip-symbolic-links','NO','YES','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','[]','','4.6','Disabling skip-symbolic-links allows MySQL to follow symbolic links, which requires an attacker to have write access to create symlinks pointing to sensitive files. This limits the attack vector but still poses a risk of partial data integrity and confidentiality issues.','Set ''skip-symbolic-links = YES'' in the MySQL configuration file (my.cnf) under the [mysqld] section.','value','always','','{"description": "The ''skip-symbolic-links'' directive in MySQL configuration prevents the server from following symbolic links when accessing files. Setting this to NO allows MySQL to follow symlinks, which can expose sensitive data and configurations if an attacker has write access.", "potential_impact": ["Expose sensitive database files", "Modify or delete critical system files through symlink attacks", "Compromise the integrity of the database by altering configuration files"], "exploitation_scenario": {"prerequisites": ["An attacker must have write permissions to create symlinks in directories accessible by MySQL", "MySQL user privileges that allow file operations"], "example": "A malicious user creates a symbolic link from /var/lib/mysql/sensitive_data.txt to /etc/passwd. When the MySQL server attempts to access sensitive_data.txt, it reads /etc/passwd instead.", "result": "The attacker can read or modify critical system files and configurations through symlink attacks."}, "metric_justifications": {"ac": "AC=M: An attacker needs write permissions on directories accessible by the MySQL server to create symlinks, which is a moderate barrier but not insurmountable.", "c": "C=P: Confidentiality of sensitive data and system files can be compromised when MySQL follows symbolic links created by an attacker.", "i": "I=P: Integrity of critical database configurations and data may be altered through symlink attacks, leading to potential misconfigurations or data corruption.", "a": "A=N: Availability is not directly impacted as the server continues to function but can lead to indirect availability issues if critical files are compromised.", "gel": "GEL=L: The likelihood of this specific misconfiguration being exploited in a real-world scenario is low, but it remains a potential risk.", "grl": "GRL=H: There is extensive documentation and guidance available on how to properly configure MySQL to mitigate symlink risks."}}','2026-06-21T23:44:37.650Z','2026-06-22T01:09:44.897Z');
INSERT INTO misconfigurations VALUES('bb4527ec-7359-4279-8f58-bab10e749c78',4,'mysql','secure_file_priv','','/path/to/safe/directory','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','["CVE-2016-6662"]','','4.8','An empty secure_file_priv setting allows an attacker to read sensitive files via SQL injection, but requires the presence of a SQL injection vulnerability and write access to the MySQL configuration file — AC is Medium. The impact is limited to partial information disclosure and potential integrity compromise within the database context.','Set ''secure_file_priv'' to NULL or a secure directory path in the [mysqld] section of the MySQL configuration file.','value','always','','{"description": "The directive secure_file_priv is intended to restrict file operations performed by LOAD DATA INFILE and SELECT ... INTO OUTFILE SQL statements. An empty or missing value for this setting allows any user with FILE privileges to read arbitrary files on the server''s filesystem via SQL injection, which can lead to sensitive data exposure.", "potential_impact": ["Disclose sensitive system files such as /etc/passwd", "Read database configuration files like my.cnf to obtain credentials", "Compromise integrity by altering critical MySQL files"], "exploitation_scenario": {"prerequisites": ["An attacker must have FILE privilege in the MySQL server.", "The presence of a SQL injection vulnerability within an application connected to the database."], "example": "A malicious user with FILE privileges can execute: SELECT ''<?php echo file_get_contents(\"/etc/passwd\"); ?>'' INTO OUTFILE ''/var/www/html/output.php'';", "result": "An attacker gains unauthorized access to sensitive system files and potentially manipulates web content or database configurations."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs both FILE privileges and a SQL injection vulnerability, which requires specific conditions to be met, making it moderately difficult but not impossible.", "c": "Why C=P: Partial information disclosure occurs as attackers can read sensitive files like system configurations or database credentials.", "i": "Why I=P: The integrity of the MySQL server is partially compromised due to potential alterations in critical configuration and data files.", "a": "Why A=N: Availability is not directly impacted, but indirect effects such as web content manipulation may occur.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited compared to other vulnerabilities because it requires specific conditions.", "grl": "Why GRL=H: There are numerous resources and documentation available for securing MySQL configurations, including the official MySQL documentation."}}','2026-06-21T23:48:00.654Z','2026-06-22T01:14:16.195Z');
INSERT INTO misconfigurations VALUES('e3b3f998-51ce-4a41-acc9-f0369727496b',4,'mysql','sql_mode','NO_ENGINE_SUBSTITUTION','NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION','N','N','L','N','P','N',5.0,4.70000000000000017,'L','H','[]','','7.4','Without NO_AUTO_CREATE_USER, a GRANT statement can accidentally create users with blank passwords, allowing partial integrity impact by creating unauthorized accounts.','Add ''NO_AUTO_CREATE_USER'' to the sql_mode setting in the MySQL configuration file (my.cnf).','value','always','','{"description": "The sql_mode directive in MySQL controls the SQL mode of the server which affects how SQL statements are executed. The value NO_ENGINE_SUBSTITUTION is not inherently dangerous but omitting NO_AUTO_CREATE_USER can lead to unintended user creation with blank passwords, compromising security.", "potential_impact": ["Allows unauthorized users to be created with empty passwords", "Enables attackers to gain partial integrity impact by creating unauthorized accounts", "Increases the risk of privilege escalation if combined with other vulnerabilities"], "exploitation_scenario": {"prerequisites": ["Access to MySQL GRANT statement execution"], "example": "A malicious user executes a GRANT statement without specifying a password, inadvertently creating an account with an empty password.", "result": "An unauthorized user is created with no password requirement, allowing easy login and potential further exploitation."}, "metric_justifications": {"ac": "AC=L: The absence of NO_AUTO_CREATE_USER in sql_mode makes it trivial for any attacker to exploit this misconfiguration by executing a GRANT statement without specifying a password.", "c": "C=N: No sensitive information is disclosed directly, but the creation of unauthorized accounts can indirectly lead to data exposure.", "i": "I=P: The integrity of the database system is compromised as new users with empty passwords can be created, potentially leading to further security breaches.", "a": "A=N: Availability is not directly impacted by this misconfiguration; however, newly created unauthorized accounts could affect service availability if exploited.", "gel": "GEL=L: This type of misconfiguration is frequently encountered in improperly configured MySQL installations and can be easily exploited once discovered.", "grl": "GRL=H: There are numerous resources available for remediation including official documentation and community forums."}}','2026-06-21T23:51:05.162Z','2026-06-22T02:13:51.328Z');
INSERT INTO misconfigurations VALUES('aedeb9ee-2bc5-439b-a2e2-60d8942347a8',4,'mysql','log_error','','/path/to/error/log','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','','6.1','Logging errors to the console instead of a file can expose sensitive information to unauthorized users who have access to the console output. This requires an attacker to gain local or remote console access, making AC Medium.','Set ''log_error'' to a specific path in the MySQL configuration file (my.cnf or my.ini).','value','always','','{"description": "The ''log_error'' directive in MySQL specifies where error logs should be written. Logging errors to the console instead of a file can expose sensitive information such as database credentials and error details to unauthorized users who have access to the console output.", "potential_impact": ["Expose sensitive information like database credentials and error messages", "Allow attackers to gain insights into system configurations and vulnerabilities", "Enable attackers to perform further reconnaissance on the system"], "exploitation_scenario": {"prerequisites": ["An attacker must have local or remote console access to the MySQL server", "The attacker needs to monitor or intercept console output"], "example": "An attacker with SSH access to a MySQL server can tail -f /var/log/mysql.err and observe error logs in real-time.", "result": "Attackers gain valuable information from error messages, aiding them in further attacks."}, "metric_justifications": {"ac": "Why AC=M: Logging errors to the console requires an attacker to have local or remote console access, which is a moderate barrier as it involves gaining unauthorized access to the system.", "c": "Why C=P: The sensitive information disclosed through error logs can be read by attackers who gain console access, leading to potential compromise of the system.", "i": "Why I=N: There is no direct impact on data or configuration modification from logging errors to the console; however, it aids in reconnaissance and further attacks.", "a": "Why A=N: Availability is not directly impacted by this misconfiguration as the service continues to function normally. However, it can indirectly affect availability if attackers use the information for more severe attacks.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited compared to other vulnerabilities but remains a risk due to its potential impact on system security.", "grl": "Why GRL=H: There are numerous resources and documentation available that explain how to properly configure MySQL logging, making it easy for administrators to remediate this issue."}}','2026-06-21T23:54:11.630Z','2026-06-22T01:27:06.564Z');
INSERT INTO misconfigurations VALUES('ff7920fb-4476-4201-8c9d-77f79c1f5913',4,'mysql','audit_log','','FORCE_PLUS_PERMANENT','N','N','M','P','P','N',5.79999999999999982,5.40000000000000035,'L','H','[]','','6.11','If the audit_log plugin can be unloaded, an attacker with sufficient privileges could disable logging temporarily or permanently, leading to partial confidentiality and integrity impacts by preventing auditing of actions.','Set ''audit_log = FORCE_PLUS_PERMANENT'' in the MySQL configuration file (my.cnf) under the [mysqld] section.','value','always','','{"description": "The audit_log directive enables logging of MySQL events for auditing purposes. Disabling this feature by setting it to an empty value allows attackers with sufficient privileges to disable logging temporarily or permanently, leading to a loss of critical audit trails.", "potential_impact": ["Compromise confidentiality and integrity of the database by preventing logging of actions", "Enable unauthorized modifications without traceability", "Reduce forensic capabilities in case of security incidents"], "exploitation_scenario": {"prerequisites": ["Sufficient privileges to modify MySQL configuration", "Access to restart or reload MySQL service"], "example": "An attacker with root access modifies the my.cnf file to remove the audit_log plugin setting and then restarts the MySQL server.", "result": "The audit logging is disabled, preventing any future actions from being logged."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs write access to the MySQL configuration files and the ability to restart or reload the MySQL service, which represents a moderate barrier.", "c": "Why C=P: Sensitive information about database actions is no longer logged, leading to potential data exfiltration without audit trails.", "i": "Why I=P: The attacker can modify the database schema or data without being recorded in logs, compromising integrity.", "a": "Why A=N: Availability of the MySQL service remains unaffected as logging does not impact performance or uptime.", "gel": "Why GEL=L: Exploitation requires specific conditions to be met and is less likely to occur frequently.", "grl": "Why GRL=H: There are extensive resources available for remediation, including official documentation on enabling audit_log."}}','2026-06-21T23:55:54.203Z','2026-06-22T01:31:09.733Z');
INSERT INTO misconfigurations VALUES('eb79d7a0-712c-4a00-a8a1-01f8a98ffb50',4,'mysql','log-bin','/var/log/mysql/bin-log.*|/usr/local/mysql/data/bin-log.*|/','/non-system-partition/path/to/binary-logs','N','N','M','N','N','P',4.29999999999999982,4.0,'L','H','[]','','6.2','Logging MySQL binary logs on the system partition can lead to denial of service if disk space is exhausted, but this requires specific conditions and does not directly expose sensitive information or allow arbitrary file writes.','Move log-bin files to a non-system partition such as /mnt/logs/mysql/','value','always','','{"description": "The MySQL directive ''log-bin'' specifies the location for storing binary logs. Storing these logs in system partitions such as /var/log/mysql/bin-log.* or /usr/local/mysql/data/bin-log.* can lead to disk space exhaustion, impacting system stability and availability.", "potential_impact": ["Exhaust disk space on critical system partitions", "Cause denial of service due to full disk conditions", "Impede database recovery operations"], "exploitation_scenario": {"prerequisites": ["An attacker must have the ability to manipulate MySQL configuration or cause excessive logging activity", "The system partition where logs are stored needs to be near capacity"], "example": "A malicious user could exploit a vulnerability that allows them to flood the binary log with large volumes of data, causing disk space exhaustion.", "result": "MySQL services may become unavailable due to lack of disk space for logging."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs specific permissions or conditions such as exploiting a vulnerability that allows them to manipulate MySQL configuration or cause excessive logging activity, which is not trivial but still feasible.", "c": "Why C=N: No sensitive information is directly exposed by this misconfiguration; however, the impact on system availability can be severe.", "i": "Why I=N: The misconfiguration does not inherently allow for arbitrary file writes or modifications to other critical configurations beyond logging.", "a": "Why A=P: Availability of MySQL services and overall system stability are significantly impacted when disk space is exhausted due to excessive binary log storage on system partitions.", "gel": "Why GEL=L: While the misconfiguration can be exploited, it requires specific conditions that may not occur frequently in all environments.", "grl": "Why GRL=H: There is extensive documentation and guidance available for securing MySQL configurations, including best practices for binary log management."}}','2026-06-21T23:58:55.666Z','2026-06-22T01:35:44.613Z');
INSERT INTO misconfigurations VALUES('9fe6f8dd-00db-4b18-901f-619dc24e182a',4,'mysql','log-warnings','1','2','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','6.3','Setting log_warnings to ''1'' enables logging of warning messages but not critical information. This can disclose communication errors and aborted connections, potentially revealing sensitive operational details.','Set ''log-warnings = 2'' in the MySQL configuration file (my.cnf) under the mysqld section.','value','always','','{"description": "The MySQL directive ''log-warnings'' is set to 1, which enables logging of warning messages but not critical information such as aborted connections and communication errors. This can potentially reveal sensitive operational details.", "potential_impact": ["Disclose communication errors that may indicate issues with database integrity or security", "Reveal aborted connections that could provide insights into failed login attempts or unauthorized access", "Expose internal MySQL operations which might aid in understanding the database environment"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker can analyze the MySQL logs to gather information about communication errors and aborted connections.", "result": "The attacker gains insights into potential security weaknesses or operational issues within the MySQL server."}, "metric_justifications": {"ac": "AC=L: The misconfiguration is easily exploitable by analyzing standard log files without any special preconditions, making it trivial for an attacker to discover sensitive information.", "c": "C=P: The configuration allows disclosure of critical communication errors and aborted connections that can be used to infer security weaknesses or operational issues.", "i": "I=N: There is no direct impact on data modification or configuration changes through this misconfiguration alone.", "a": "A=N: Availability is not directly impacted by the logging level set to 1, but sensitive information disclosure could indirectly affect system security.", "gel": "GEL=M: Misconfigurations like this are moderately exploited as they provide valuable insights for attackers without requiring complex techniques.", "grl": "GRL=H: Remediation documentation is widely available and straightforward, making it easy to correct the misconfiguration."}}','2026-06-22T00:00:34.841Z','2026-06-22T01:39:43.365Z');
INSERT INTO misconfigurations VALUES('c405bd49-409e-449c-ae3a-fef32e285c14',4,'mysql','log-raw','ON','OFF','N','N','L','C','N','N',7.79999999999999982,7.79999999999999982,'M','H','[]','','6.4','Enabling log-raw allows plain text passwords to be logged, exposing sensitive information to anyone with access to the logs.','Set ''log-raw = OFF'' in the MySQL configuration file (my.cnf).','value','always','','{"description": "The ''log-raw'' directive in MySQL logs all raw queries to the error log. When set to ON, it includes plain text passwords in these logs, exposing sensitive information to unauthorized users who can access the logs.", "potential_impact": ["Expose database credentials", "Allow unauthorized access to the database", "Compromise data integrity and confidentiality"], "exploitation_scenario": {"prerequisites": ["Access to MySQL error log files"], "example": "An attacker with read access to the MySQL error logs can easily find plain text passwords in the raw query logs.", "result": "The attacker gains unauthorized access to the database using the exposed credentials."}, "metric_justifications": {"ac": "AC=L: An attacker only needs read access to the MySQL error log files, which is trivial for someone with low-level system privileges or a misconfigured file permissions setup.", "c": "C=C: The logs contain sensitive information such as plain text passwords and other critical data that can be used to compromise the database.", "i": "I=N: There is no direct impact on modifying data or configuration through this vulnerability, but it enables lateral movement within the system.", "a": "A=N: Availability of services is not directly impacted by logging raw queries; however, the risk of service disruption increases due to potential misuse of exposed credentials.", "gel": "GEL=M: Misconfigurations like enabling ''log-raw'' are moderately common and can be exploited frequently if discovered.", "grl": "GRL=H: There is extensive documentation available on how to remediate this issue, including official MySQL guides and security advisories."}}','2026-06-22T00:02:08.134Z','2026-06-22T01:43:42.988Z');
INSERT INTO misconfigurations VALUES('ca9a2186-1266-494e-942f-d8c4ead44413',4,'mysql','audit_log_connection_policy','NONE','ERRORS|ALL','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','6.5','Setting audit_log_connection_policy to NONE disables logging of failed and successful connection events, allowing attackers to evade detection for malicious activities.','Set ''audit_log_connection_policy'' to either ERRORS or ALL in the MySQL configuration file to ensure proper auditing of connection events.','value','always','','{"description": "The audit_log_connection_policy directive in MySQL controls whether connection events are logged. Setting this to NONE disables logging of both successful and failed connection attempts, which can allow attackers to evade detection for malicious activities.", "potential_impact": ["Allows unauthorized access without trace", "Enables lateral movement within the network undetected", "Hinders forensic analysis after a breach"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can exploit this misconfiguration by attempting to brute-force login credentials or using stolen credentials. Since logging is disabled, these activities leave no trace in the audit logs.", "result": "The attacker gains unauthorized access and performs malicious actions without being detected."}, "metric_justifications": {"ac": "AC=L: Setting audit_log_connection_policy to NONE makes it easy for any attacker to exploit this misconfiguration by simply attempting login attempts, as there are no logging barriers.", "c": "C=P: The configuration detail is publicly readable and can be easily discovered through SQL queries or MySQL documentation.", "i": "I=N: There is no direct impact on data integrity since the misconfiguration does not allow for unauthorized modification of data or configurations beyond evading detection.", "a": "A=N: Availability is unaffected as disabling logging does not disrupt service availability, but it hinders monitoring and response efforts.", "gel": "GEL=M: This type of misconfiguration can be exploited moderately frequently due to its ease of discovery and exploitation.", "grl": "GRL=H: There are numerous resources available for remediation, including official MySQL documentation and security guidelines."}}','2026-06-22T00:05:07.499Z','2026-06-22T01:47:45.951Z');
INSERT INTO misconfigurations VALUES('0cadc554-69e5-4a03-952d-1aad07faa1ec',4,'mysql','audit_log_exclude_accounts','','NULL','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','6.6','Setting audit_log_exclude_accounts to an empty string allows any user''s activities to go unlogged, potentially enabling malicious actions without trace in the audit log.','Set ''audit_log_exclude_accounts = NULL'' to ensure all user activities are logged appropriately.','value','always','','{"description": "The directive ''audit_log_exclude_accounts'' is intended to specify accounts whose activities should not be logged. Setting this value to an empty string allows any user''s actions to go unlogged, potentially enabling malicious actions without trace in the audit log.", "potential_impact": ["Allows unauthorized access and activity to remain undetected", "Enables attackers to perform actions that can compromise data integrity and confidentiality", "Facilitates lateral movement within the system by hiding the attacker''s footprint"], "exploitation_scenario": {"prerequisites": ["An attacker with any level of MySQL user access"], "example": "Setting audit_log_exclude_accounts = '''' in the MySQL configuration file to disable logging for all users.", "result": "All user activities are no longer logged, allowing malicious actions to go undetected."}, "metric_justifications": {"ac": "Why AC=L: Setting ''audit_log_exclude_accounts'' to an empty string is trivially exploitable by any MySQL user with access, as it requires only changing the configuration setting.", "c": "Why C=P: The attacker can potentially gain full control over the system without leaving a trace in logs, leading to potential data exfiltration and other malicious activities.", "i": "Why I=N: While the misconfiguration does not directly modify data or configurations, it enables attackers to perform actions that can compromise integrity and confidentiality.", "a": "Why A=N: The availability of the system is not directly impacted by this misconfiguration; however, it indirectly affects security posture by enabling undetected malicious activities.", "gel": "Why GEL=M: This type of misconfiguration is moderately likely to be exploited as it provides a significant advantage to attackers in covering their tracks.", "grl": "Why GRL=H: There are extensive remediation steps and documentation available for securing MySQL configurations, making it relatively easy to correct this issue."}}','2026-06-22T00:06:53.880Z','2026-06-22T01:52:12.822Z');
INSERT INTO misconfigurations VALUES('87f28ea0-27c1-4be3-ac7f-a4bd09f23c2d',4,'mysql','audit_log_include_accounts','','NULL','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','','6.7','Setting audit_log_include_accounts to an empty string allows only explicitly listed MySQL accounts to be logged, potentially excluding malicious activity from the audit log. This requires insider or local access to modify the configuration.','Set ''audit_log_include_accounts = NULL'' in my.cnf or execute ''SET GLOBAL audit_log_include_accounts = NULL;''','value','always','','{"description": "The directive ''audit_log_include_accounts'' should be set to NULL to ensure that all MySQL accounts are logged by default. Setting it to an empty string can exclude certain activities from being audited, potentially allowing malicious actions to go undetected.", "potential_impact": ["Allows unauthorized access attempts and suspicious activities to remain unlogged", "Enables attackers with insider knowledge or local access to evade detection", "Reduces the ability of security teams to track and respond to potential threats"], "exploitation_scenario": {"prerequisites": ["An attacker must have write access to MySQL configuration files or execute SQL commands as a superuser", "The attacker needs knowledge of the current audit_log_include_accounts setting"], "example": "SET GLOBAL audit_log_include_accounts = '''';", "result": "All accounts except those explicitly listed in the audit log will not be logged, allowing malicious activities to go unnoticed."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs write access to MySQL configuration files or execute SQL commands as a superuser, which is a moderate barrier but still achievable for insiders with certain privileges.", "c": "Why C=P: The information disclosed includes potential evasion of audit trails and the ability to hide malicious activities from security monitoring systems.", "i": "Why I=N: While the configuration can be modified, there is no direct data or configuration modification impact beyond altering logging behavior.", "a": "Why A=N: Availability is not directly impacted as MySQL continues to function normally; however, the lack of comprehensive audit logs may hinder incident response efforts.", "gel": "Why GEL=L: This type of misconfiguration can be exploited by insiders with specific privileges but is less likely to be discovered and used by external attackers without such access.", "grl": "Why GRL=H: There are numerous resources available for remediation, including official MySQL documentation and security guidelines."}}','2026-06-22T00:08:48.704Z','2026-06-22T01:56:44.505Z');
INSERT INTO misconfigurations VALUES('f07ea0a0-8351-4921-8311-1e7ad7e15ca6',4,'mysql','old_passwords','1','0','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','7.1','Setting ''old_passwords'' to 1 uses a weak hashing algorithm, making it easier for attackers to crack passwords if they are captured. This can lead to partial confidentiality impact as sensitive information may be compromised.','Set ''old_passwords'' to 0 or 2 to use the mysql_native_password or sha256_password plugin respectively.','value','always','','{"description": "The ''old_passwords'' directive in MySQL determines whether to use the old or new password hashing algorithm. Setting it to 1 enables the weaker MySQL native password hashing method, which is vulnerable to offline brute-force attacks and makes passwords easier to crack.", "potential_impact": ["Compromise sensitive information through cracked passwords", "Enable unauthorized access to databases with weak credentials", "Reduce overall security posture due to outdated encryption methods"], "exploitation_scenario": {"prerequisites": ["Access to a MySQL database", "Captured password hashes"], "example": "An attacker captures the password hash of a user and uses a tool like John the Ripper or Hashcat to crack it offline, exploiting the weak hashing algorithm.", "result": "The attacker gains unauthorized access to the database using the cracked credentials."}, "metric_justifications": {"ac": "Why AC=L: Setting ''old_passwords'' to 1 makes password cracking trivial for attackers with captured hashes and common tools, requiring no special conditions beyond sending a request.", "c": "Why C=P: The confidentiality of sensitive information is partially compromised as weak passwords can be easily cracked offline.", "i": "Why I=N: There is no direct impact on data or configuration modification through this misconfiguration alone.", "a": "Why A=N: Availability is not directly impacted by the ''old_passwords'' setting, but successful exploitation could indirectly affect availability if critical services are compromised.", "gel": "Why GEL=M: This type of misconfiguration is frequently exploited due to its ease and the widespread use of weak password hashing algorithms.", "grl": "Why GRL=H: There is extensive documentation available on how to remediate this issue, including official MySQL guides."}}','2026-06-22T00:12:08.879Z','2026-06-22T02:00:58.206Z');
INSERT INTO misconfigurations VALUES('a0d142f5-801f-4f53-84d2-d69ec6fc450f',4,'mysql','secure_auth','OFF','ON','N','N','M','P','N','N',4.29999999999999982,4.0,'L','H','[]','','7.2','Disabling secure_auth allows clients to use accounts with passwords stored in the insecure mysql_old_password format, enabling attackers who can authenticate using these accounts to exploit vulnerabilities related to weak or outdated encryption.','Set ''secure_auth=ON'' to prevent connections from clients using old password formats and ensure secure communication over the network.','value','always','','{"description": "The directive secure_auth is designed to prevent clients from using accounts with passwords stored in the insecure mysql_old_password format. Disabling this feature (secure_auth=OFF) allows connections from clients using these outdated password formats, increasing vulnerability to attacks exploiting weak encryption.", "potential_impact": ["Allows attackers to authenticate using weak or outdated password hashes", "Enables exploitation of vulnerabilities related to old authentication methods", "Increases the risk of unauthorized access due to insecure communication"], "exploitation_scenario": {"prerequisites": ["An attacker must have knowledge of a username and its corresponding mysql_old_password hash", "The attacker needs network access to attempt connections"], "example": "An attacker uses a tool like John the Ripper or Hashcat to crack an old password hash, then connects to the MySQL server using the cracked credentials.", "result": "Successful authentication with an insecure password format grants the attacker unauthorized access to the database."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs knowledge of a specific username and its corresponding mysql_old_password hash, which requires reconnaissance or prior compromise. This moderate barrier makes exploitation more challenging than trivial but not extremely difficult.", "c": "Why C=P: The disclosure of sensitive data is possible through unauthorized access granted by insecure authentication methods.", "i": "Why I=N: While the attacker can gain unauthorized access, there are no specific mechanisms in place to allow for direct modification or deletion of critical configurations or data beyond what standard user privileges permit.", "a": "Why A=N: The availability of services is not directly impacted by this misconfiguration; however, successful exploitation could lead to denial-of-service if the attacker disrupts normal operations through unauthorized access.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited in practice due to the increasing adoption of more secure authentication methods and practices.", "grl": "Why GRL=H: There are numerous resources available for understanding and mitigating this risk, including official MySQL documentation and security advisories."}}','2026-06-22T00:14:05.288Z','2026-06-22T02:09:37.656Z');
INSERT INTO misconfigurations VALUES('66354f4b-4042-467b-975d-52c1065d588b',4,'mysql','have_ssl','NO','YES','N','N','L','P','N','N',5.0,5.0,'H','H','[]','','8.1','Disabling SSL/TLS allows plaintext traffic, exposing data to eavesdropping and man-in-the-middle attacks. Any remote attacker can intercept sensitive information.','Set ''have_ssl'' to ''YES'' and configure SSL/TLS as per the MySQL Reference Manual.','value','always','','{"description": "The ''have_ssl'' directive enables SSL/TLS encryption for MySQL connections. Disabling it (value NO) allows plaintext traffic, exposing sensitive data to interception and man-in-the-middle attacks.", "potential_impact": ["Expose database credentials and sensitive information in transit", "Allow attackers to intercept and modify data during transmission", "Enable eavesdropping on communication between the MySQL server and clients"], "exploitation_scenario": {"prerequisites": ["None"], "example": "An attacker sniffs network traffic to capture unencrypted database credentials and queries.", "result": "The attacker can read or modify data in transit, leading to unauthorized access and potential data breaches."}, "metric_justifications": {"ac": "Why AC=L: Disabling SSL/TLS (have_ssl=NO) makes it trivial for any remote attacker to intercept plaintext traffic without needing additional privileges.", "c": "Why C=P: Confidentiality is partially compromised as sensitive data can be read by attackers who intercept network communications.", "i": "Why I=N: Integrity of the data in transit is not directly affected, but attackers can modify intercepted data leading to potential injection attacks or data corruption.", "a": "Why A=N: Availability is not directly impacted; however, denial-of-service scenarios could arise if attackers exploit vulnerabilities introduced by plaintext communication.", "gel": "Why GEL=H: Misconfigurations like disabling SSL/TLS are frequently exploited due to the ease of capturing sensitive information in plain text.", "grl": "Why GRL=H: Remediation steps for enabling SSL/TLS are well-documented and widely available, making it straightforward to correct this misconfiguration."}}','2026-06-22T00:17:23.807Z','2026-06-22T02:17:54.897Z');
INSERT INTO misconfigurations VALUES('a4c3d01e-4313-4ab1-a68c-c9d892066dad',4,'mysql','ssl_type','','ANY,X509,SPECIFIED','N','N','L','P','N','N',5.0,5.0,'M','H','[]','','8.2','Not enforcing SSL/TLS allows eavesdropping and man-in-the-middle attacks, exposing sensitive data in transit. However, it does not provide full system access or immediate availability impact.','Use the GRANT statement to require SSL for users connecting over untrusted networks: GRANT USAGE ON *.* TO ''my_user''@''app1.example.com'' REQUIRE X509;','value','always','','{"description": "The ssl_type directive specifies the SSL/TLS requirements for MySQL connections. Not setting this to ANY, X509, or SPECIFIED allows unencrypted communication between clients and the server, exposing sensitive data in transit.", "potential_impact": ["Expose database traffic to eavesdropping", "Allow interception of authentication credentials", "Enable man-in-the-middle attacks"], "exploitation_scenario": {"prerequisites": [], "example": "An attacker can intercept network traffic between a MySQL client and server, capturing unencrypted data.", "result": "The attacker gains access to sensitive information such as database queries, credentials, and other confidential data."}, "metric_justifications": {"ac": "Why AC=L: An attacker can easily eavesdrop on or intercept unencrypted MySQL traffic without any special preconditions beyond being able to monitor the network.", "c": "Why C=P: The confidentiality of sensitive information such as database queries and credentials is compromised, allowing an attacker to read this data.", "i": "Why I=N: While SSL/TLS configuration affects security, it does not inherently provide mechanisms for modifying data or configurations directly through this misconfiguration alone.", "a": "Why A=N: The availability of the system is not directly impacted by the lack of SSL/TLS enforcement; however, sensitive data exposure can indirectly affect trust and operational integrity.", "gel": "Why GEL=M: This type of misconfiguration is commonly exploited due to its ease of detection and exploitation in environments where security practices are lax.", "grl": "Why GRL=H: There is extensive documentation available on how to properly configure SSL/TLS for MySQL, making remediation straightforward."}}','2026-06-22T00:20:32.368Z','2026-06-22T02:22:02.610Z');
INSERT INTO misconfigurations VALUES('9c171876-cf6f-4c2b-a409-64b0cb47eef7',4,'mysql','master_info_repository','FILE','TABLE','N','N','M','P','C','N',7.79999999999999982,7.29999999999999982,'L','H','[]','','9.3','Setting master_info_repository to ''FILE'' stores the password in a plaintext file, which can be accessed by an attacker with filesystem permissions. This allows modification of the slave''s connection information and potential unauthorized access.','Set ''master_info_repository = TABLE'' to store the password securely within the database tables.','value','always','','{"description": "The directive master_info_repository controls where MySQL replication master information is stored. Setting it to ''FILE'' stores this sensitive data in plaintext files on disk, which can be accessed by unauthorized users with filesystem permissions.", "potential_impact": ["Expose the replication password and other sensitive configuration details", "Allow an attacker to modify the slave''s connection information", "Enable unauthorized access to the master server through compromised credentials"], "exploitation_scenario": {"prerequisites": ["An attacker with filesystem permissions on the MySQL data directory"], "example": "An attacker reads the plaintext file containing replication details and modifies it to redirect traffic or steal credentials.", "result": "The attacker gains unauthorized access to the master server''s replication configuration, potentially leading to data theft or service disruption."}, "metric_justifications": {"ac": "Why AC=M: An attacker needs filesystem permissions on the MySQL data directory, which is a moderate barrier compared to trivially exploitable configurations.", "c": "Why C=P: The replication password and other sensitive configuration details are readable in plaintext files.", "i": "Why I=C: The slave''s connection information can be modified, leading to potential unauthorized access or redirection of traffic.", "a": "Why A=N: Availability is not directly affected by this misconfiguration, but it may lead to service disruption if the attacker uses the compromised credentials.", "gel": "Why GEL=L: This type of misconfiguration is less frequently exploited compared to more common vulnerabilities like SQL injection or XSS.", "grl": "Why GRL=H: There are extensive remediation guidelines and documentation available for securing MySQL replication configurations."}}','2026-06-22T00:22:18.416Z','2026-06-22T02:26:02.620Z');
INSERT INTO attack_chains VALUES(1,1,'apache-httpd','directory-traversal-chain','["Options", "AllowOverride"]',1.5,'Options FollowSymLinks or Indexes combined with AllowOverride All allows user-controlled .htaccess to escalate privileges and enable directory traversal or execution of arbitrary scripts.',0,'2026-06-20T01:42:43.048Z');
INSERT INTO attack_chains VALUES(2,1,'apache-httpd','dos-amplification','["Timeout", "KeepAliveTimeout", "MaxKeepAliveRequests"]',1.39999999999999991,'Permissive Timeout + KeepAliveTimeout + unbounded MaxKeepAliveRequests create compounding resource exhaustion vectors. An attacker can hold connections open and multiply the DoS impact.',0,'2026-06-20T01:42:43.050Z');
INSERT INTO attack_chains VALUES(3,1,'apache-httpd','info-disclosure-chain','["ServerTokens", "ServerSignature"]',1.30000000000000004,'Both ServerTokens and ServerSignature leaking version details compound the information disclosure risk, giving attackers precise version targeting.',0,'2026-06-20T01:42:43.053Z');
INSERT INTO attack_chains VALUES(4,1,'apache-httpd','load-module-status-on','["LoadModule", "ServerTokens"]',1.39999999999999991,'Enabling the status module with LoadModule and setting ServerTokens to Full reveals detailed server information, aiding attackers in reconnaissance and targeted exploitation.',0,'2026-06-20T01:42:43.055Z');
INSERT INTO attack_chains VALUES(5,1,'apache-httpd','load-module-status-userdir','["LoadModule", "User"]',1.60000000000000008,'Loading the status_module and setting User to root allows an attacker to access detailed server statistics via /server-status, which can be exploited for further reconnaissance or privilege escalation.',0,'2026-06-20T01:42:43.057Z');
INSERT INTO attack_chains VALUES(6,1,'apache-httpd','options-all-status-module','["Options", "LoadModule"]',1.39999999999999991,'Enabling Options All and loading the status_module allows an attacker to access detailed server statistics via /server-status, which can be used for further reconnaissance or denial of service attacks.',0,'2026-06-20T01:42:43.059Z');
INSERT INTO attack_chains VALUES(7,1,'apache-httpd','options-indexes-autoindex-module','["Options", "LoadModule"]',1.39999999999999991,'Enabling Options Indexes and loading the autoindex_module allows directory listings to be displayed, which can expose sensitive file structures and facilitate further reconnaissance or exploitation.',0,'2026-06-20T01:42:43.061Z');
INSERT INTO attack_chains VALUES(8,1,'apache-httpd','privilege-escalation','["User", "Group"]',1.60000000000000008,'Setting User and Group to root grants the Apache server full administrative privileges, allowing an attacker who gains access through any vulnerability to escalate their privileges immediately.',0,'2026-06-20T01:42:43.068Z');
INSERT INTO attack_chains VALUES(9,1,'apache-httpd','request-smuggling-chain','["LimitRequestLine", "LimitRequestFields", "LimitRequestFieldSize"]',1.39999999999999991,'Overly permissive request size limits across line, fields, and field size create compounding HTTP request smuggling and buffer overflow risk when multiple limits are misconfigured together.',0,'2026-06-20T01:42:43.071Z');
INSERT INTO attack_chains VALUES(10,1,'apache-httpd','server-tokens-full-sslprotocol-all','["ServerTokens", "SSLProtocol"]',1.39999999999999991,'Setting ServerTokens to Full and SSLProtocol to All provides detailed information about the server''s software version, which can be used by an attacker for targeted exploitation or reconnaissance.',0,'2026-06-20T01:42:43.074Z');
INSERT INTO attack_chains VALUES(11,1,'apache-httpd','webdav-rce-chain','["LoadModule", "AllowOverride"]',1.69999999999999995,'WebDAV modules (dav_module, dav_fs_module) loaded with permissive AllowOverride enables remote file upload and execution. This chain has the highest amplification — remote code execution in one step.',0,'2026-06-20T01:42:43.076Z');
INSERT INTO attack_chains VALUES(12,2,'nginx','server-info-to-tls-downgrade','["server_tokens", "ssl_protocols"]',1.39999999999999991,'Step 1 (server_tokens on) discloses the exact Nginx version in every HTTP response header, allowing an attacker to identify the specific OpenSSL version in use. Step 2 (ssl_protocols with SSLv3 or TLSv1/TLSv1.1) enables deprecated protocol versions with known cryptographic weaknesses. Together, version disclosure enables the attacker to precisely target the exposed TLS implementation with protocol-specific exploits (POODLE, BEAST), converting a passive information leak into an active MitM downgrade attack. Full path: reconnaissance via Server header → identify vulnerable TLS version → protocol downgrade attack.',0,'2026-06-20T01:49:46.694Z');
INSERT INTO attack_chains VALUES(13,2,'nginx','dos-resource-exhaustion','["send_timeout", "client_max_body_size", "keepalive_timeout"]',1.5,'Step 1 (send_timeout 0) removes the upper bound on how long Nginx waits for a client to receive a response, keeping worker connections open indefinitely for slow clients. Step 2 (client_max_body_size 0) removes request body size limits, allowing arbitrarily large uploads that consume memory and I/O. Step 3 (keepalive_timeout 0 or 65) compounds the attack surface: a value of 0 disables keepalive entirely, forcing a new connection per request and exhausting connection slots, while an excessive value holds connections open beyond reasonable use. Together, these three directives remove all throttling mechanisms and allow a low-bandwidth attacker to exhaust Nginx worker connections with minimal resources. Full path: initiate many slow connections → hold workers open indefinitely → exhaust server capacity.',0,'2026-06-20T01:49:46.695Z');
INSERT INTO attack_chains VALUES(14,2,'nginx','unencrypted-proxy-with-weak-tls','["proxy_pass", "ssl_protocols"]',1.39999999999999991,'Step 1 (proxy_pass to http://) routes backend traffic over unencrypted HTTP within the internal network, exposing credentials, session tokens, and API responses to any attacker with network access to the internal segment. Step 2 (ssl_protocols with weak protocols) means the client-facing connection is also potentially weak, enabling a MitM attacker to simultaneously intercept both the external TLS session (via downgrade) and the cleartext internal hop. Together, these directives create an end-to-end exposure path: attacker downgrades the external TLS session, then reads the cleartext proxy-to-backend channel. Full path: TLS downgrade on client connection → intercept cleartext proxy_pass channel → capture sensitive data.',0,'2026-06-20T01:49:46.697Z');
INSERT INTO attack_chains VALUES(18,4,'mysql','skip-grant-tables-log-raw','["skip-grant-tables", "log-raw"]',1.60000000000000008,'The ''skip-grant-tables'' directive allows anyone to bypass authentication and access the database without any restrictions, while ''log-raw'' logs detailed information about all SQL queries in a raw format. Together, these misconfigurations enable an attacker to gain full administrative control over the MySQL server by logging into it without credentials and viewing sensitive data through logged queries.',0,'2026-06-22T09:28:32.927Z');
INSERT INTO attack_chains VALUES(19,4,'mysql','allow-suspicious-udfs-log-raw','["allow-suspicious-udfs", "log-raw"]',1.60000000000000008,'''Allow-suspicious-udfs'' enables the use of potentially dangerous user-defined functions, which can be exploited to execute arbitrary code on the server. Combined with ''log-raw'', an attacker can gain detailed insights into SQL queries and system operations, facilitating further exploitation through UDFs.',0,'2026-06-22T09:28:32.936Z');
INSERT INTO attack_chains VALUES(20,4,'mysql','master-info-repository-file-log-raw','["master_info_repository", "log-raw"]',1.60000000000000008,'''Master_info_repository=FILE'' stores replication master information in a file, which can be read to obtain sensitive data such as passwords and server addresses. When combined with ''log-raw'', an attacker gains detailed logs of all SQL queries, including those related to replication, making it easier to exploit the stored replication information.',0,'2026-06-22T09:28:32.939Z');
