che 2.4.x - Buffer Overflow", "type": "webapps", "verified": true, "cve": "CVE-2021-44790", "path": "/home/albertojf/exploitdb/exploits/multiple/webapps/51193.py"}, {"edb_id": "9993", "title": "Apache mod_perl - ''Apache::Status'' / ''Apache2::Status'' Cross-Site Scripting", "type": "remote", "verified": true, "cve": "CVE-2009-0796", "path": "/home/albertojf/exploitdb/exploits/multiple/remote/9993.txt"}, {"edb_id": "25852", "title": "ModSecurity - Remote Null Pointer Dereference", "type": "dos", "verified": false, "cve": "CVE-2013-2765", "path": "/home/albertojf/exploitdb/exploits/multiple/dos/25852.py"}, {"edb_id": "50446", "title": "Apache HTTP Server 2.4.50 - Remote Code Execution (RCE) (2)", "type": "webapps", "verified": false, "cve": "CVE-2021-42013", "path": "/home/albertojf/exploitdb/exploits/multiple/webapps/50446.sh"}]','2026-06-22T11:29:13.736Z');
